window.__LIBQ=window.__LIBQ||{};window.__LIBQ["the-gioi-hoan-my"]=window.__LIBQ["the-gioi-hoan-my"]||{};window.__LIBQ["the-gioi-hoan-my"]["q02"]=window.__LIBQ["the-gioi-hoan-my"]["q02"]||{};window.__LIBQ["the-gioi-hoan-my"]["q02"]["cotTruyen"]=[{"chuong":101,"tieuDe":"Một Búa Quật Ngã","tomTat":"Nhóc tỳ trinh sát hang Hắc hổ Thú Vương ở khu đất trống sát khí dày đặc rồi rút lui vì quá nguy hiểm; qua chữ ghi niên đại cạnh Hắc Sát Liên nó xác nhận Thú Vương do Bổ Thiên các hàng phục để trấn thủ. Nó dùng cự thạch phủ phù văn khiêu khích sáu bảy con bá chủ mãnh thú tạo thành thú triều hỗn loạn, dụ Hắc hổ rời hang, rồi phóng vào đào trộm Hắc Sát Liên và bỏ chạy, bôi chất lỏng lên hai con Thanh Lang để xóa dấu vết. Chìm đáy sông tu hành suốt đêm luyện hóa dược tính, nó mở khẩu thứ sáu Động Thiên khi mới 9 tuổi rưỡi. Quay lại chiến trường thứ hai tan hoang, nó gặp liên minh nhỏ bại trận than về Tiêu Thiên quá cường đại. Tiêu Thiên — thanh niên áo bào bạc thu 16 khối Bổ Thiên thạch, thắng cả thiếu niên Mộc tộc — vẫn bất an vì một đứa nhỏ giấu mặt từng bị hắn đánh lén. Nhóc tỳ ẩn thân ra tay, dùng Bạch cốt đại bổng như búa đánh hai đòn sau gáy, khiến kẻ mạnh nhất hơn chín vạn người bị một búa quật ngã."},{"chuong":102,"tieuDe":"Thật Đáng Thương","tomTat":"Nhóc tỳ dùng Bạch cốt đại bổng đánh lén Tiêu Thiên — thiếu niên áo bào bạc được xưng thiên hạ đệ nhất thiên tài — ngất hai búa để báo thù việc từng bị đánh lén lúc bị Cổ Ngạc đuổi giết, rồi lục soát cướp 25 khối Bổ Thiên thạch cùng 2 bình bảo đan. Tiêu Thiên tỉnh dậy đau đầu dữ dội, mọc cục u như sừng trên trán và nhận ra kẻ tấn công là đứa nhỏ hắn từng đánh chưởng cướp Bổ Thiên thạch. Tin khu thứ tám bạo động lan truyền: phù cốt bị cướp sạch khiến trận vực mất hiệu lực, tổ đoàn hơn 8900 người xông cửa ải cuối thành công, các thiếu niên nhận ra phong cách tên nhóc siêu quậy ở Hư Thần giới. Bổ Thiên các nhượng bộ, Hùng Phi và Trác Vân trưởng lão cùng tộc lão cắn răng cho phép 3000 người thông qua. Nhóc tỳ lo bị lộ danh tính nên chạy trốn ngược qua khu thứ ba, rồi gặp lại Tiêu Thiên, đánh lén lần hai nện lên cục u chưa lành và ném trả bao Bổ Thiên thạch đã mất hiệu lực, dặn cả vốn lẫn lời phải hoàn lại. Cuối cùng nó tiện tay nhặt lại một Đế tử bị bỏ sót rồi than mình đáng thương, cô đơn xoay người hướng về khu thứ tám."},{"chuong":103,"tieuDe":"Thần Vũ Ngút Trời","tomTat":"Không cam lòng rời đi, Thạch Hạo trong lốt nhóc tỳ khắc lên tảng đá cứng dòng chữ 'Thần vũ ngút trời, quang minh chính đại' cùng câu khoe về cây búa, rồi đánh xuyên tấm chắn phù văn khu thứ tám, đuổi hung cầm chiếm tổ chim mà ngủ. Sáng hôm sau nó gặp hai huynh muội đang nướng chim, cướp ăn rồi dò hỏi và bật cười khi biết Bổ Thiên Các đã bày thiên la địa võng phong tỏa chiến trường thứ hai để bắt chính 'thằng ranh nhân thần cộng phẫn' là nó, còn cho người ngoài xem lễ. Trước khi chia tay, nó tặng hai huynh muội mỗi người một viên Long Tán và Hổ Dược lột được từ Tiêu Thiên. Vì lần này tuyển ba nghìn môn đồ nên độ khó cửa ải hạ thấp, nhóc tỳ trà trộn vào một tổ đội xông ra rồi lách vào chiến trường thứ hai, khiến các trưởng lão Hùng Phi và Trác Vân cay đắng thề tính sổ. Ở chiến trường thứ hai, Tiêu Thiên tỉnh dậy trong khe đá bị bịt kín, phát hiện hơn hai mươi viên Bổ Thiên Thạch bị cướp nay được trả lại đầy đủ nhưng bản thân vẫn bị đập búa đến mọc một cục u như sừng trên trán. Hắn phẫn uất nổi điên thi triển Âm Ba Công, tiếng rống chấn động sơn hà khiến các trưởng lão tưởng lầm là kỳ tài ngút trời mà tranh nhau khen ngợi. Cuối cùng Trác Vân hé lộ Bổ Thiên Các sở hữu một gốc linh dược chăm bằng Hắc Hổ Sát, tương lai có thể lột xác thành Thánh Dược, dùng để oai chấn tứ phương chiêu mộ thiên tài."},{"chuong":104,"tieuDe":"Ung Dung Bình Tĩnh","tomTat":"Đám tiền bối các thế lực khiếp phục khi hay tin Bổ Thiên Các gây trồng được Thánh Dược, thứ có thể cải tử hoàn sinh vốn cực hiếm ở Đại Hoang, nên nôn nóng chờ được chiêm ngưỡng. Hùng Phi trưởng lão dẫn mọi người đi ngắm các thiếu niên tài tuấn trước, gặp Tiêu Thiên áo bạc phong thái siêu phàm, nhưng khi hắn quay lại lộ ra cục u to như sừng trên trán khiến các trưởng lão phải khéo léo gọi đó là 'thiên tướng' để không đắc tội. Tiêu Thiên ném ra túi da thú chứa 28 viên Bổ Thiên Thạch, đứng đầu bảng, được tán tụng là hạt giống đáng bồi dưỡng, dù trong lòng hắn căm hận vì bị kẻ trong bóng tối nện hai búa gây nên cục u. Đi tiếp, đoàn phát hiện dãy núi khu thứ tám bị tàn phá tan hoang, nghe kể về một bóng người bí ẩn chủ động khiêu khích các hung thú bá chủ gây thú triều rồi dẫm bật qua cả đỉnh núi, khiến các trưởng lão nổi giận quyết truy tìm thằng siêu quậy. Trác Vân trưởng lão vẫn ung dung khuyên mọi người giữ hình tượng, rồi dẫn đoàn tới hố đất do Hắc Hổ Sát canh giữ để giới thiệu Thánh Dược Hắc Sát Liên đã 800 năm tuổi sắp lột xác. Nhưng khi giơ tay chỉ, ông chết lặng nhận ra Hắc Sát Liên đã bị đào sạch cả gốc lẫn ngọn, chỉ còn cái hố trống, khiến vẻ điềm tĩnh sụp đổ và hóa thành cơn cuồng nộ như người điên."},{"chuong":105,"tieuDe":"Khảo Nghiệm Kết Thúc","tomTat":"Trác Vân trưởng lão của Bổ Thiên các đang hiền hòa tiếp khách bỗng phát điên gào thét khi phát hiện Hắc Sát Liên trong địa quật đã biến mất, các trưởng lão hốt hoảng lục soát trước sự chê cười của đám khách mời. Hắc hổ khổng lồ từ địa quật bước ra tỏa sát khí, truyền thần niệm cảnh báo đây là kế điệu hổ ly sơn rồi lui vào bóng tối. Hùng Phi và các trưởng lão nhanh chóng quy tội cho nhóc tỳ siêu quậy từng náo loạn Hư Thần Giới, xác nhận qua cái hố nhảy đặc trưng và mảnh linh dược in dấu răng nhỏ, hóa ra bảo dược đã bị nhai sống cả gốc chỉ để đột phá đệ lục Động Thiên. Bổ Thiên các bày thiên la địa võng phong tỏa chiến trường thứ hai, huy động toàn bộ đệ tử nhưng chỉ tìm được sáu trong mười tám bộ bảo cốt bị giấu, trong khi nhóc tỳ đã đổi hình dạng trà trộn giữa ba ngàn đệ tử. Các trưởng lão đành tuyên bố khảo nghiệm kết thúc, mắt lóe xanh dò xét từng thiên tài vì nghi kẻ trộm lẩn trong đó, đồng thời suy đoán hắn là ấu tể của thái cổ hung thú hóa hình người. Một thiếu niên áo bào bạc ôm thù kẻ đập mình hai búa lại bị đám đông hiểu lầm là anh hùng tâm tính siêu phàm khi ngửa mặt nhìn trời. Cuối cùng Bổ Thiên các công bố kết nạp toàn bộ người vượt qua làm đệ tử, ban truyền thừa Thượng cổ Tịnh thổ, đoàn người tiến về sơn môn nơi Thạch Nghị cùng nhóm quyền quý đã chờ sẵn cho nghi thức nhập môn."},{"chuong":106,"tieuDe":"Tội phạm truy nã của Tịnh Thổ","tomTat":"Sau khi các tộc lão Đại Hoang ly biệt con em, ba ngàn thiếu niên qua khảo nghiệm được dẫn vào Bổ Thiên các nơi Thượng cổ Tịnh Thổ, trong khi gần chín vạn người bị loại. Nhóc tỳ - vốn là nhân vật chính đã biến hình thành mập ục ịch - giả khóc bám vào một cụ già xa lạ để trà trộn nhập môn, rồi lập tức bỏ đi khi vừa được an ủi. Nó quấy nhiễu khắp nơi, thèm ăn linh cầm linh dược, dò hỏi về con gái Nhân Hoàng và Trùng Đồng giả cùng những nhân vật lai lịch lớn đã rời đi sớm. Khi nghi thức bái Tổ sư vừa xong, một tảng đá nghi là Tế Linh được đưa tới, hiện lên hai câu chữ khiêu khích do chính Nhóc siêu quậy để lại, khiến ba ngàn người kinh hoảng nhận ra kẻ khét tiếng. Trưởng lão Hùng Phi phát lệnh truy nã ngay trong nội bộ, buộc Nhóc tỳ phải trốn vào đám đông và giả vờ hô bắt chính mình, rồi trớ trêu bị chính Hùng Phi và Trác Vân - hai người từng bị nó chọc đến hộc máu - chọn làm đệ tử. Được thiếu nữ áo trắng an trí ở khu núi đá và học văn tự Hoàn Cốt, Nhóc tỳ giả vui nhưng trong lòng ưu sầu, lại được dặn tránh xa Tế Cư của Tế Linh. Cuối cùng, không thấy Bóng Lông đâu suốt mấy ngày, nó phát hiện Thanh Phong bị thương đầy máu ứ, âm thầm nổi giận và quyết hỏi cho ra lẽ dù đang phải cẩn trọng giữa Bổ Thiên các."},{"chuong":107,"tieuDe":"Vô Đề","tomTat":"Cả Hư Thần giới bàn tán sôi nổi về nhóc tỳ khi nó đào Bảo Cốt khu thứ tám, trộm Bảo Dược và lưu tảng đá khắc ‘Búa Ở Trong Tay, Ta Có Thiên Hạ’ ở chiến trường thứ hai; Hùng Phi và Trác Vân trưởng lão tức phun máu, phát lệnh truy nã, còn khối u trên đầu Tiêu Thiên bị đồn là do nhóc tỳ nện búa khiến hắn suýt nổi khùng. Ở khu núi đá cạnh rừng trúc, nhóc tỳ làm đệ tử mới phải xách nước linh tuyền, khai thác quặng tinh kim, bất mãn vì hai lão già chỉ dạy thứ nó đã biết; một thiếu niên giải thích chỉ người thiên phú nghịch thiên mới được truyền Cốt Văn và Bảo Thuật. Bóng Lông trở về sau nhiều ngày, bị nhóc tỳ tóm đuôi, kể chuyện lang thang Linh sơn khí lành nguy hiểm mới hái được một cây linh thảo, rồi được sai đi điều tra Thanh Phong. Thanh Phong ngồi một mình tự xử vết thương, bị bọn thiếu niên thiên tài trong thiên tài doanh đánh bầm nửa người và cấy Phù Văn chạy loạn phá tu hành nhằm đào thải nó để thế chỗ, nhưng nó quyết kiên trì tới đầu tháng lấy Dược Tán và Cốt Thư, đồng thời ghi nhớ kinh văn Tế Linh giúp tiểu ca ca. Bóng Lông lén tới thăm, nghe kể mọi chuyện rồi về báo sau nửa đêm; nhóc tỳ mặt đen kịt vạch kế trừng trị, nghi chỗ dựa của bọn kia là Vũ gia Thạch Quốc và tính lôi kéo Thạch Nghị vào cuộc. Hai ngày sau, một đám thiên tài của thiên tài doanh — tuấn kiệt các bộ tộc lớn — kéo tới vùng núi đá để phô diễn sự chênh lệch cho đệ tử mới, đúng thời điểm nhóc tỳ hẹn ra tay."},{"chuong":108,"tieuDe":"Thiên Tài Doanh","tomTat":"Nhóm thiên tài đưa hơn ba ngàn đệ tử mới tới rừng trúc khu nhập môn. Vũ Phong ra mặt kêu gọi hòa khí, nhiều đệ tử mới thách đấu nhưng đều bại: thiên tài áo xám dùng tường Linh hỏa thiêu Thải Cưu, thiên tài cao to phô Kim Tuyền Ba Văn Công xoắn nát trường mâu. Tiêu Thiên một chiêu thắng rồi nổi gân xanh cố nhịn kích động. Chu Vũ Hào giả bộ sư huynh ôn hòa nhưng dùng Ngư Long Phù Văn kèm ám kình đánh trọng thương Thanh Phong đến ngũ tạng bể nát, rồi mượn cớ khơi thông huyết mạch hại thêm lần nữa. Nhóc tỳ trốn trong đám đông quan sát, thấy Thanh Phong bị hại thì ra tay đấm Chu Vũ Hào nở hoa mặt, hô hoán vu hắn là đồng bọn nhóc siêu quậy, kích động mấy trăm đệ tử đuổi đánh đến răng bay hộc máu. Có người hỏi vì sao Thạch Nghị cùng con gái Nhân Hoàng và hơn chục kỳ tài đặc biệt không xuất hiện, được đáp là bị lão quái vật đưa đi."},{"chuong":109,"tieuDe":"Xung Đột Đẫm Máu","tomTat":"Chu Vũ Hào bị mấy trăm rồi hơn ngàn thiếu niên các bộ lạc đánh hội đồng vì trước đó tự nhận biết chỗ nhóc siêu quậy rồi bỏ chạy; một Phù Chưởng thần bí đánh gãy xương sườn trái hắn, khiến hắn ngã xuống bị giẫm đạp gãy hết răng. Hai người thân của Chu Vũ Hào nhảy vào cứu cũng bị Phù Chưởng đánh gãy xương. Thạch Hạo trà trộn trong đám đệ tử mới hô hào kích động, ra quyền đầu và ra tay trọng thương ba người rồi lui về sau đắc ý, biến vụ việc thành nội chiến hơn ba ngàn người dùng Phù Văn đối kháng. Một ông lão ngồi trước sơn môn triệu hồ lô vỏ vàng từ hư không nuốt hết bão táp như cá voi hút nước, ra lệnh kẻ cầm đầu diện bích ba năm rồi rời đi. Trưởng lão Hùng Phi và Trác Vân điều tra nhưng không tìm ra kẻ cầm đầu, chỉ có mấy kẻ xui xẻo bị thương nặng; Trác Vân chửi mắng Chu Vũ Hào rồi cả hai thu hồi Khuyển Ma Công. Sư tỷ tiết lộ hồ lô là chí bảo Bổ Thiên các do Tế Linh (một giàn dây hồ lô) kết ra. Vài ngày sau, Thạch Hạo đi khắp Bổ Thiên các mênh mông và nhìn thấy Thạch Nghị đang bước trên con đường không tận cùng vào Thượng Cổ Thánh Viện, cộng hưởng đại đạo và được lợi ích lớn dù chưa vào."},{"chuong":110,"tieuDe":"Tế Linh Của Tịnh Thổ","tomTat":"Nhóc tỳ từ bỏ ý định vào Thượng Cổ Thánh Viện khi biết nơi ấy mấy chục đến mấy trăm năm mới mở một lần cho một người, lần này Bổ Thiên các đã chọn Thạch Nghị, đồng thời thoáng thấy một thiếu niên như thần đang bước trên con đường vào Thánh Viện. Nắm đuôi Bóng Lông, nó rón rén lẻn vào khu vườn cổ hơn trăm dặm nơi Tế Linh ở ẩn, khu vực không ai dám tới gần. Càng vào trong đất càng hoang vu hóa sa mạc vì bị một luồng sức mạnh ma quái hút mất địa khí, khiến thần hi trong người nó bộc phát Phù Văn dày đặc; nó đoán Tế Linh đang tu bí công hút địa khí nuốt thiên tinh. Đến khu vườn cổ ba tầng còn sót lại, nó thấy Tế Linh của Bổ Thiên các chỉ là một giàn dây hồ lô ố vàng ốm yếu sắp tàn nhưng vẫn uy nghiêm như thần linh, và dưới đám lá khô có một trái hồ lô màu xanh chứa khí Hỗn Độn khiến nó lẫn Bóng Lông muốn hái nhưng bị bản năng ngăn lại. Nó ngồi tu hành dưới Tế Linh, quán tưởng Nguyên Thủy Chân Giải và nhận ra khi Phù Văn hồ lô xanh lấp loé kèm thiên địa đạo âm thì việc lĩnh ngộ dễ dàng hơn nhiều. Khi rời đi, nó sởn tóc gáy chạm mặt một lão già tóc xám mắt trống rỗng, đầu bị cổ kiếm rỉ sét xuyên thủng, không sinh mệnh mà di chuyển như hư không, phát tiếng ô ô như khóc rồi chặn đứng đường đi của nó."},{"chuong":111,"tieuDe":"Chuyện Thần Quái Từ Thời Thượng Cổ","tomTat":"Tại nơi ở Tế Linh trong Thượng Cổ Tịnh Thổ, một ông lão tử khí Thượng Cổ tóc xám nhuốm máu đen, cổ kiếm rỉ sét cắm trên đầu, liên tục cản đường Thạch Hạo và tái tạo từ hư không mỗi khi bị né. Nhóc tỳ chạy về cầu cứu Tế Linh nhưng giàn dây hồ lô khô vàng bất động; khi định chạm trái hồ lô vỏ xanh, nó phát khí Hỗn Độn hiển hóa Phù Văn đẩy lui nó. Ông lão lặp lại “Trả kiếm cho ta”, nhóc tỳ hứa sau này tìm giúp trả kiếm khiến trời đất biến sắc sấm chớp, ông lão biến mất. Sáu ngày sau ông lão hiện lần hai bên giường, các đệ tử không nhìn thấy nhưng sờ được như tượng băng lạnh thấu xương, cả đám kinh hoàng bỏ chạy. Trưởng lão Hùng Phi và Trác Vân biến sắc, tiết lộ đây là chuyện thần quái Thượng Cổ cách mấy trăm năm xuất hiện một lần tất chết người, rồi chạy đi mời lão tiền bối. Cuối chương nhóc tỳ hết sợ, lại cưỡi lên cổ ông lão tóc xám; đồng thời một ông lão phương xa nâng hồ lô vàng óng đầy khí Hỗn Độn xuất hiện, khiến cao tầng Bổ Thiên các chấn động cùng xuất quan chạy tới."},{"chuong":112,"tieuDe":"Là Chết Hay Là Cơ Duyên","tomTat":"Nhóc tỳ giấu thân phận cưỡi trên cổ một vị thần quái Thượng Cổ bị cổ kiếm đâm xuyên đầu, dùng đỉnh đồng gõ leng keng đốm lửa tứ tung để nhổ thanh kiếm mà nó tưởng là Bảo Cụ chí cường, khiến hơn ba nghìn thiếu niên trợn mắt vì lá gan của nó. Đám trưởng lão Bổ Thiên các dẫn đầu là Đào Dã cầm hồ lô vàng óng khí Hỗn Độn bay tới giải cứu, nhưng nhóc tỳ tưởng họ tới cướp kiếm nên ôm chặt đề phòng. Trác Vân giải thích đây là thần quái Thượng Cổ, mỗi lần xuất hiện đều có người phải chết, khiến nhóc tỳ hoảng nhảy bám các trưởng lão suýt bóp Hùng Phi tắt thở. Cả đám hộ tống nó tới đại điện nghị sự Bổ Thiên các, nơi Đào Dã tiết lộ vị thần quái xưng Tử Thần cách mấy trăm năm xuất thế một lần cùng dịp Bách Đoạn sơn mở ra, ai bị Hắn chọn trúng mà không giúp được đều chết. Thanh kiếm cắm đầu Hắn là của đối thủ ngày xưa, còn kiếm thật của Hắn rơi mất ở Bách Đoạn sơn mạch cần nhóc tỳ tìm về nếu không sẽ chết. Đào Dã nói nay nơi đó khác xưa, chứa cơ duyên lớn, nếu Tử Thần chọn nhóc tỳ thì Bổ Thiên các được thêm một suất, ngay cả di chủng thuần huyết Li Long, Thao Thiết cũng đưa dòng dõi vào, khiến nhóc tỳ trợn mắt kinh ngạc."},{"chuong":113,"tieuDe":"Thân Phận Bại Lộ","tomTat":"Các nguyên lão Bổ Thiên các thuyết phục nhóc tỳ vào Bách Đoạn sơn, giải thích rằng đây là mảnh đất đầy cơ duyên nhưng chỉ người dưới mười tám tuổi mới vào được nên chúng buộc phải cậy nhờ nó. Nhóc tỳ cảnh giác, mặc cả đòi chỗ tốt và tuyên bố muốn bắt một con Kim Sí Đại Bằng non khiến cả đoàn cứng đơ. Khi được đưa xuống bàn bạc, bốn lão tiền bối mắt ánh xanh thử thân thể nó, nhưng nó phản kích một đấm chấn động cung điện, khiến các lão kinh ngạc khen thân thể nghịch thiên. Ngay lúc đó Hùng Phi nhận ra nó chính là 'thằng nhóc quỷ' từng gây loạn hại hắn và Trác Vân khốn đốn, thân phận bại lộ. Bốn lão dỗ dành và giao cho nó nhiệm vụ tìm Bất Lão thần tuyền mang về, đổi lại được khắc tên lên Bất Hủ Thần Bi và vào Tàng Kinh các chọn Bảo Thuật. Sau khi bị bắt quả tang trộm ăn Tuyết Ngọc Sâm rồi đổ cho Đào Dã 'cho', nó được thả tự do tu hành, rồi mang một cây linh dược nguyên vẹn tới Thiên tài doanh tặng 'đệ đệ' Thanh Phong. Nó công khai mở kèo đánh cược quanh cây linh dược, khiêu khích cả đám thiếu niên lẫn thiếu nữ; một thiếu nữ áo xanh cùng vài người khác lần lượt bước lên nhận khiêu chiến để đoạt lấy linh dược."},{"chuong":114,"tieuDe":"Vô Đề","tomTat":"Một đám thiên tài vây lấy nhóc tỳ ở Thiên tài doanh định dạy dỗ, nhưng nó bày trò “đổ chiến” cá cược buộc ai muốn đánh phải đặt chiến lợi phẩm xuống đất. Nhóc tỳ (Thạch Hạo) dùng Phù Văn hai tay dệt búa bạc đánh tan Khổng Tước xanh của Ngạn Tâm rồi khống chế bắt sống nàng, tạo cối xay bạc nghiền tan chiến mâu của Phiêu Tuyết. Nó đánh gục Chu Vũ Hào — kẻ trước khi hôn mê nhận ra nhóc tỳ chính là ca ca của Thanh Phong; rồi thắng liên tiếp 28 trận không ai địch nổi, chấn động toàn khu. Thạch Hạo công khai tuyên bố ai bắt nạt Thanh Phong là bắt nạt nó, khích lệ đệ đệ tu hành; Vũ Phong áo trắng được giục ra áp chế nhưng chỉ lắc đầu không xuất thủ. Sau nhiều ngày kết giao bạn bè, nhóc tỳ dặn dò Thanh Phong rồi lên đường tới Bách Đoạn sơn, nơi Đào Dã cho biết con gái Nhân hoàng, Thạch Nghị cùng hậu duệ Thái cổ di chủng đã được hộ tống đến trước. Các trưởng lão cảnh báo đệ tử về con non Thái Cổ hung thú và người đồng trang lứa mạnh không thể đánh bại, dặn phải tìm cách sống sót. Tại nơi ở của Tế Linh, các trưởng lão thu mảnh xương Thái cổ di chủng, rồi một hồ lô màu xanh hiện lên dựng thành thông đạo màu xanh; đoàn người đi vào và biến mất khỏi Bổ Thiên các."},{"chuong":115,"tieuDe":"Đoạn Không Thành","tomTat":"Đoàn Bổ Thiên các theo nguyên lão Đào Dã vượt qua con đường Thanh Kim do Tế Linh tạo ra, nơi thời gian như vỡ vụn và linh hồn tưởng chừng tách khỏi thân xác, rồi tiến vào Đoạn Không thành — một cổ thành di tích của cổ quốc từng huy hoàng nhưng đã suy tàn sau đại chiến. Đây là điểm tập kết trước khi Bách Đoạn sơn, nơi mấy trăm năm mới mở một lần, khai môn thu hút thiên kiêu khắp Đại Hoang. Trong thành, một nữ đệ tử lỡ lời khiến đoàn xung đột với tiểu Bạch Hổ của Tây Lăng thú sơn, buộc Đào Dã phải rút hồ lô Phù Văn xưng danh Bổ Thiên các để dằn mặt, đối phương hẹn quyết chiến trong Bách Đoạn sơn. Trên đường còn có Sở Hạ nhà Sở gia đến từ Hỏa quốc chào mời kết minh nhưng bị thiếu niên họ Cổ mỉa mai từ chối, rồi một thiếu niên nuôi Linh Tước năm màu thả yêu cầm nuốt sống mấy chục kẻ đang tranh đấu khiến cả phố lặng ngắt. Nhóc tỳ tinh nghịch dò la tin tức thì phát hiện mình bị nhiều thế lực truy lùng, có phe ra lệnh bắt sống, và đoán kẻ săn mình phần lớn là gia tộc đã mất Xích Vũ Bảo Phiến mà nó đang giữ. Giữa lúc đó, một Thái Cổ di chủng khổng lồ bay ngang che khuất mặt trời, phủ sát khí mênh mông, báo hiệu chinh chiến khốc liệt sắp diễn ra trong Bách Đoạn sơn nơi chôn giấu Bất Lão thần tuyền, truyền thừa Võ Thánh cùng vô số Thiên cốt và Thánh dược."},{"chuong":116,"tieuDe":"Bão Táp Tích Trữ","tomTat":"Đoạn Không thành náo nhiệt khi thiên tài các đại giáo và gia tộc cổ tề tựu, chuẩn bị tiến vào tiểu thế giới Bách Đoạn sơn. Nhóc tỳ giả dạng đi cùng đội năm thiên tài Bổ Thiên các, chạm trán Thái Cổ di chủng Phì Di, né được đòn đuôi rồi lớn tiếng cảnh cáo ngược khiến cả phố sững sờ, còn Phì Di thì cảm nhận từ nó một khí tức hung mãnh giống hệt mình. Trên đường, nó thấy đủ loại dị chủng kỳ lạ như người kim loại, đá biết nói, Liệt Thiên Ma Điệp, và được sư tỷ giải thích Bách Đoạn sơn thực chất là một tiểu thế giới. Tiền thưởng bắt đầu nó tăng gấp đôi, nhiều kẻ chịu đổi Bảo Cụ, Cốt Thư, Linh Dược để lấy đầu nó, có người suy đoán nó ẩn trong đội Bổ Thiên các nên chỉ cần bám theo. Tại tế đàn cổ của chư Thánh, một con Hoàng Kim sư tử chín đầu hống lên tuyên bố đã chọn 'kẻ nhân loại' kia làm nô bộc và cấm kẻ khác tranh giành. Cách đó tám ngàn dặm, Vũ tộc ở Hoàng Đô Thạch quốc dựa vào tin của Phong nhi cài trong Bổ Thiên các, xác định danh tính nó là Hạo Thiên, thấy nó có nét giống Thạch Tử Lăng năm xưa, liền ra lệnh sau khi vào Bách Đoạn sơn phải quấn lấy và có cơ hội thì diệt trừ không kiêng kỵ."},{"chuong":117,"tieuDe":"Bách Đoạn Sơn","tomTat":"Nửa tháng sau, biên giới tận cùng vùng đất bốc sương rồi nổ vang long trời; người già xác nhận thông đạo mở ra, Bách Đoạn Sơn — một tiểu thế giới độc lập cách nơi này bằng vô tận hư không — tái hiện thế gian. Các tiền bối báo đây là cơ may hiếm có: vào trong có thể chiếm đại cơ duyên hoặc chết không chỗ chôn thây, nơi này từng sản sinh Nhân hoàng và giáo chủ tối cao. Đoạn Không thành náo loạn khi mọi chủng tộc kéo tới, khí Hỗn Độn cuộn trào như sóng biển nhưng bị thành ngăn lại đúng như tên gọi. Muôn loài sinh linh tranh nhau lao vào sương mù, còn bao tải 「bảo bối」 của Nhóc Tỳ bị lộ chỉ là nồi niêu xoong chảo trưng dụng từ nhà bếp, khiến Đào Dã đen mặt vì mất danh Bổ Thiên các. Nhóm Bổ Thiên các qua cửa vào thông đạo, lao ra một tiểu thế giới linh khí đậm đặc gần đọng thành nước, có hồ trong, cổ dược và bốn gốc linh dược trên vách núi. Vừa vào rừng núi, Nhóc Tỳ đã tung hoành như rồng về biển: đụng gãy một cao thủ Thụ tộc hóa cây định đánh lén, rồi đuổi bắt chim lửa Đại Hồng và Nhân Hùng một sừng đen để làm đồ ăn. Các thiên tài Bổ Thiên các sững sờ, còn thiên tài các chủng tộc quanh đó kinh sợ lùi bước trước sự hung hãn của tiểu sư đệ."},{"chuong":118,"tieuDe":"Thằng Bé Hung Tàn","tomTat":"Một tiểu tử Nhân tộc thuộc Bổ Thiên các, được gọi là thằng bé hung tàn, truy đuổi Nhân Hùng một sừng màu đen để lấy tay gấu nhưng con mồi chạy thoát. Khi Hỏa Vân Tước nổi giận trút thác lửa, nó triệu khay bạc thần thánh chắn thế lửa rồi dùng Ma Cầm thời Thái Cổ, tia chớp vàng và vầng trăng bạc đánh cho con chim rớt thịt phải giả chết trốn đi. Nhóc tỳ nhặt hơn hai chục cân thịt đem nấu cùng sư huynh sư tỷ, ăn xong cả người phát sáng vì đó là huyết nhục bảo dược tăng tinh khí. Bên hồ nước có bốn gốc Xích Lan mọc trên vách núi, một sinh vật hình người ánh bạc khí tức lạnh giá xuất hiện, đạp sập vách đá thả cự thạch vạn cân định chôn vùi sư huynh đang hái dược, nhóc tỳ nhảy vào lôi người ra cứu. Kẻ ánh bạc đối chiếu bức tranh xác nhận nhắm đúng nhóc tỳ, ngắt sạch Linh dược rồi chiêu dụ nó làm chiến bộc, tự xưng là vương và chủ nhân của nó, hứa sau sẽ thả về Nhân tộc chiếm đất xưng vương. Nhưng nhóc tỳ chỉ đen mặt đi vòng quanh ngắm nghía, chê kẻ kia toàn xương lại là hình người khó ăn, bực tức tính chuyện chôn sống hay hấp cách thủy con mồi lạ này."},{"chuong":119,"tieuDe":"Thu Hoạch Di Chủng","tomTat":"Một sinh linh màu bạc (Thái Cổ di chủng hậu duệ Vương tộc) bị Thạch Hạo đòi ăn thịt nên tức giận thu ngân quang lộ chân thân thân người phủ vảy bạc, tự xưng “Vương tương lai” rồi lao vào đánh. Không địch nổi bằng sức thân thể, hắn vận Phù Văn cùng bảo phiến bạc và chủy thủ bạc, nhưng Thạch Hạo triển bảo thuật Toan Nghê Vương qua Cốt Kính phản chiếu ánh sáng làm hắn thủng bả vai. Thạch Hạo rút Cốt Tiễn vàng bẻ gãy chủy thủ, chặt đứt cánh tay trái rồi đuổi theo cắt cổ, đánh đầu lâu đối thủ thành tro. Nhặt được chiến lợi phẩm nhưng cây quạt bạc đã nát hơn nửa khiến Thạch Hạo bi phẫn, đồng môn kinh hãi vì độ giàu chí bảo của tiểu sư đệ. Không muốn ăn sinh linh hình người vì sợ ám ảnh, Thạch Hạo nghe sư huynh gợi ý bèn hô lớn rao đổi Thái Cổ di chủng, làm dãy núi rung động và có người đáp lại. Vượt một dãy núi, nhóm gặp hơn bốn mươi thiên tài hộ tống xe phượng đỏ thẫm — con gái nhỏ của Nhân Hoàng, sư muội cùng môn — và hai bên đồng ý thỏa thuận trao đổi."},{"chuong":120,"tieuDe":"Bảy Động Thiên","tomTat":"Nhóc tỳ rao trao đổi con sinh linh màu bạc mà nó chém giết; người mặc áo khoác đen giọng khàn từ chỗ xe kéo ra xác nhận đây là Linh Tộc, Thái Cổ di chủng cực hiếm có Vương huyết truyền thừa. Thiếu nữ hoàng tộc trong xe quyết đổi bằng Tử Vân Tâm — trái tim của Tử Vân Điêu mà nhóm thiên tài đã hao tổn chém giết — dù nhiều người can là không đáng. Nhóc tỳ trêu gọi công chúa là sư muội vì cùng Bổ Thiên các; thiếu nữ ~15-16 tuổi con gái được Nhân Hoàng sủng ái nhất vén rèm bước ra, lộ tên Hỏa Linh Nhi khi cười nhạo, rồi cả đám nhận ra đó là nhóc siêu quậy đang bị truy nã nên nhào tới vây bắt, nó bỏ chạy vào rừng biến mất. Vài ngày sau trong hang cổ, nhóc tỳ luyện hóa Tử Vân Tâm đột phá, mở ra miệng Động Thiên thứ bảy với dung nham cuồn cuộn chảy vào cơ thể, khí tức kinh khủng khiến mãnh thú chạy trốn. Nó bay tới khe núi nơi có xe kéo công chúa, đánh chết sinh linh mọc sừng người của Vũ Vương dám rủ nó làm tôi tớ, rồi bắn mười tia chớp giết luôn mấy Dị tộc còn lại. Cuối cùng công chúa Hỏa quốc kìm nén kích động chiêu mộ nhóc tỳ, tiết lộ đã liên hệ Hoàng Kim sư tử chín đầu, Vũ Vương, Ngân Huyết Cự Nhân để đi Thần Quật đoạt chí bảo; nhóc tỳ đồng ý nhưng ôm thù muốn hầm con sư tử dị dạng, rồi vỗ mông công chúa để trêu ngược lời dọa đánh mông của nàng."},{"chuong":121,"tieuDe":"Cảnh Ngộ","tomTat":"Hỏa Linh Nhi, công chúa Hỏa quốc và là sư muội ở Bổ Thiên các, nổi giận phun lửa hóa Chu Tước đánh nhóc tỳ, nhưng bị nó bung Nguyệt bàn màu bạc chắn lại và năm vị thiên tài can ngăn. Nàng ra điều kiện tha thứ là khi tới Thần Quật không được xung đột với Hoàng Kim sư tử chín đầu, nhưng nhóc tỳ lại chọc nàng 'giảm béo', khiến nàng phát điên dệt cánh Chu Tước truy sát, biến cả thảo nguyên thành biển lửa. Tới chân núi Thần Quật, đoàn người chạm mặt ba Thái Cổ di chủng cầm đầu là Hoàng Kim sư tử chín đầu, người khổng lồ Ngân Huyết và Vũ Vương, cùng đám thiên tài Nhân tộc đã bị hàng phục làm tôi tớ. Cả ba tranh nhau muốn thu nhóc tỳ làm chiến sủng, nhưng nó ngạo mạn từ chối và tuyên bố ngược lại muốn bắt chúng làm tôi tớ. Trong đại chiến một chọi ba, nhóc tỳ đấm Ngân Huyết chảy máu tay, đá Vũ Vương văng ra hộc máu, rồi dùng bảo cốt Toan Nghê thi triển 'Nghịch chuyển' phản đòn Sư Tử chín đầu, đánh lui hai kẻ và ngang sức với sư tử khiến cả trường kinh hãi. Nhóc tỳ điềm nhiên thừa nhận đã ăn thịt Mộc Phong của Linh tộc, tuyên bố mục đích vào Bách Đoạn sơn là hàng phục cho bằng được một Thái cổ hung thú non như con của Chân Hống hay hậu duệ Kim Sí Đại Bằng. Hoàng Kim sư tử chặn ải, chín đầu phun chín phi kiếm hoàng kim, còn Hỏa Linh Nhi vừa bị nhóc tỳ trêu vừa sốt ruột giục sư tử mau thu phục kẻ ngông cuồng này."},{"chuong":122,"tieuDe":"Đánh Bại Sư Tử Chín Đầu","tomTat":"Trời về chiều, trên thảo nguyên mênh mông của Đại hoang, Nhóc tỳ đại chiến Hoàng Kim sư tử (Sư Tử chín đầu) tuy cảnh giới thấp hơn vẫn đánh ngang tài, khiến Dị tộc và người xem kinh hãi. Sư tử tung Sư Hống công, chín răng nanh phi kiếm do trưởng bối tặng và chuỗi niệm châu vàng, nhưng bị Cốt Tiễn (Kim Giao tiễn) của Nhóc tỳ làm một đầu lâu suýt nứt, trọng thương; sau cú va chạm Thần Huy cả hai đều phun máu, đây là lần đầu Nhóc tỳ bị thương kể từ khi vào Tiểu Thế Giới. Sư tử liền tung thần thông trấn tộc Vô Úy Sư Tử ấn khiến thiên tài Bổ Thiên các trắng bệch mặt, nhưng Nhóc tỳ vận Nguyên Thủy Chân Giải cùng Chiến Thần Đồ Lục, biến hóa Phù Văn mấy chục lần mà hóa giải. Ngộ ra chiến đấu đỉnh cấp không cần đại thần thông, Nhóc tỳ chỉ tổ hợp Phù Văn thường cũng phá tan chiêu này. Hoàng Kim sư tử tiêu hao quá nhiều tinh khí thần nên bỏ chạy, bị Nhóc tỳ nhảy lên cưỡi và dùng sấm sét trấn áp. Cuối cùng Nhóc tỳ do dự giữa việc làm thịt hay giữ Sư Tử chín đầu — vốn thuộc mười tọa kỵ hàng đầu thời Thượng cổ — làm thú cưỡi, khiến các sinh linh chứng kiến khiếp sợ vì quá hung tàn."},{"chuong":123,"tieuDe":"Thần Quật","tomTat":"Sư Tử chín đầu huyết thống cao quý phẫn nộ chống trả nhóc tỳ đang cưỡi trấn áp nó, tung chín hạt niệm châu và răng nanh hóa phi kiếm, nhưng nhóc tỳ hóa thân sấm sét chống ngang lực rồi dùng Cốt Tiễn hóa giao long chém rụng bốn đầu lâu, khiến Sư Tử bại trận bỏ trốn vào một lỗ đen giữa sườn núi được gọi là Thần Quật. Nhóc tỳ từ chối vào theo vì cảm giác nơi này quỷ dị, để Hỏa Linh Nhi dẫn đoàn thiên tài Nhân tộc cùng Ngân Huyết và Vũ Vương tiến vào; nó cùng các sư huynh sư tỷ Bổ Thiên các ở lại, hầm bốn đầu lâu chứa thần tính với linh dược thành lò bảo dược cùng ăn. Năm thiên tài Bổ Thiên các nhờ đó lần lượt đột phá, riêng nhóc tỳ ăn phần lớn nhưng từ chối đột phá ngay để hòa tinh khí thần tạo cơ sở vững, do vừa mượn Tử Vân Tâm mở ra Động Thiên thứ bảy. Nửa đêm bầy sói dị chủng có tổ chức cùng mấy chục Lang Vương vây công, khiến các thế lực bên trong nhận ra đây thực là Ma Quật — vùng đất trầm tịch của Lang Thần nuôi sói. Sáng ra các đoàn thoát ra đầy thương vong, Hỏa Linh Nhi đoạt được một quả trứng vàng nghi là hậu duệ Lang Thần khớp với chữ khắc trên vách. Khi trứng rơi ra giữa cuộc tranh cướp hỗn loạn, nhóc tỳ vọt tới ôm chặt đòi luộc ăn rồi xông qua bầy sói biến mất, để cả đám kêu thảm truy đuổi."},{"chuong":124,"tieuDe":"Nướng Ra Một Thần Linh","tomTat":"Nhóc tỳ Thạch Hạo cướp được trứng thần màu vàng và ôm chạy, bị cả đám người truy đuổi nhờ mùi U Lan Thảo vẩy lên trứng. Đại thảo nguyên bạo động ban đêm, vô số cự lang cùng mấy chục Lang Vương hiểu Bảo Thuật quần công; nhóc tỳ dùng Cốt Tiễn màu vàng phá vòng vây, đạp bảo kính Toan Nghê bay cao rồi nhảy xuống sông lớn cắt mùi trốn thoát. Nó suy đoán trứng có thể là hậu duệ Thần linh sánh vai hung thú Thái Cổ, nhắc mục đích lớn nhất khi vào Tiểu Thế Giới là bắt một hung thú Thái Cổ non về Thạch thôn, và tiết lộ mặt trời của thế giới này thực chất là thi thể Thái Cổ Kim Ô. Cho rằng trứng đã hư, nhóc tỳ nhóm lửa nồi sắt quyết định nướng/luộc để lấy vật chất thần tính. Đoàn Hỏa Linh Nhi, Ngân Huyết cự nhân, Vũ Vương chạy vòng cả đêm rồi quay về điểm xuất phát, tức đến hộc máu, nhờ U Lan Thảo tìm ra nhóc tỳ và xông vào đại chiến; năm vị thiên tài Bổ Thiên các ra tay giúp nó. Trong lúc nhóc tỳ dùng trứng làm lá chắn, lửa và tia điện đập vào khiến vỏ nứt vỡ, cuối cùng một thần linh non thực sự nở ra, cuộn tròn trong lòng bàn tay."},{"chuong":125,"tieuDe":"Ấu Thần","tomTat":"Một sinh linh nhỏ bé bọc trong ánh sáng ngũ sắc ra đời giữa vòng vây tranh đoạt, hấp thu sạch mọi bảo thuật, mưa sáng và tia điện để trưởng thành, lộ hình sói con lông xám có sừng nhú cùng đôi cánh nhỏ — hậu đại của Lang Thần và được nhận ra là một Ấu Thần. Nhóc tỳ Nhân tộc bọc lấy nó xông ra, dùng chớp và Cốt Tiễn vàng kim đánh cháy tay người khổng lồ Ngân Huyết, chặt gãy hung đao và đứt một cánh tay Vũ Vương, buộc đám truy đuổi rút lui. Dùng Tham Cốt pháp trong Nguyên Thủy Chân Giải thăm dò sói con nhưng chỉ thấy máu huyết mạnh mà không có phù cốt hay ấn ký, nhóc tỳ hoãn lại đợi cảnh giới cao hơn. Sói con quyến luyến bám vai nhóc tỳ, được Hỏa Linh Nhi cho ăn Linh dược và trái tim hung thú, còn nhóc tỳ hỏi 'có sữa không' khiến nàng nổi giận đuổi đánh suốt hai giờ, lộ biệt danh cũ 'Thích Uống Sữa Thú Nhất' ở Hư Thần Giới. Ngân Huyết và Vũ Vương bị truy sát bắt trói, còn Sư Tử chín đầu — cháu Cửu Linh Vương, thuần huyết từng giết thần — bị nhóc tỳ đại chiến rồi thu phục làm thú cưỡi kiêm tiểu đệ, bị ép đòi đại lễ Linh dược, Thánh dược và giúp tìm Bất Lão Thần Tuyền. Sư Tử chín đầu phát thệ khuất phục sau khi nhận ra sói con chính là Ấu Thần. Ở nơi khác, Vũ tộc tụ tập dưới mưa hấp thu sức mạnh, tra khảo Độc Giác Nhân Hùng và quyết mai phục chờ thiếu niên hung tàn xuất hiện."},{"chuong":126,"tieuDe":"Vũ Tộc","tomTat":"Thạch Hạo cưỡi Sư Tử chín đầu — di chủng Vương tộc Thái Cổ có thuần huyết đã bị hắn hàng phục làm tọa kỵ — xông qua núi rừng khiến vạn thú tránh né, rồi chia tay công chúa Hỏa quốc và các thiên tài Bổ Thiên các để đi tìm Bất Lão Thần Tuyền. Thạch Hạo đòi mượn xem chuỗi niệm châu vàng và kim kiếm của Sư Tử nhưng bị kiên quyết từ chối, hai bên tranh cãi uy hiếp qua lại, Sư Tử dọa tự bạo. Phát hiện cường giả Nhân tộc mai phục ở thông đạo, Thạch Hạo nghi có bộ tộc muốn luyện Cửu Chuyển Linh Đan cần sáu giọt bảo huyết Thái Cổ nên nhắm bắt Sư Tử. Đổi hướng sang vùng ngập nước sương mù, hai người sa vào năm tầng sát trận Phù Văn cổ, dùng Kim Giao tiễn và chuỗi niệm châu phá trận, cuối cùng thoát ra với vài vết thương nhẹ. Mười thiếu niên cường giả Vũ tộc tới, kinh sợ khi nhận ra người hàng phục được Sư Tử chín đầu, rồi hiện bảo quang trong mưa. Một người kể chuyện tám năm trước bộ tộc điều cao thủ đánh vợ chồng Thạch Tử Lăng máu nhuộm Tây Cương để thăm dò thân phận Thạch Hạo, hé lộ ân oán mẫu thân Thạch Nghị (Vũ tộc) đã trộm Chí Tôn cốt của Thạch Hạo đưa vào con trai. Thạch Hạo lạnh lùng không đáp, chỉ vung bảo kính trong tay ra tay phản kích."},{"chuong":127,"tieuDe":"Săn Bắn Trong Mưa","tomTat":"Trong tiểu thế giới ao hồ đầm lầy mưa giăng, mười thiên tài Vũ tộc phát hiện bảo cụ trên tay nhóc tỳ liền hợp lực thi triển các Bảo Thuật thủy hệ như Tà phong tế vũ Trảm tinh nguyệt và Thông thiên động địa, uy lực ngang hai ba mươi người, đè ép cả một vùng núi. Nhóc tỳ cùng Sư Tử chín đầu phản kích bằng lôi đình từ bảo cốt Toan Nghê chuyên khắc chế Vũ tộc, nước dẫn điện khiến cả nhóm cháy đen thành tro. Trước khi chết, kẻ sống sót nhận ra cậu chính là đứa trẻ mất Chí Tôn cốt hơn tám năm trước và tiên đoán một đại sát kiếp, rồi cũng bị bắn nổ tung. Nhóc tỳ tiếp tục truy sát khắp vùng đầm lầy, giết tổng cộng hai mươi thiên tài Vũ tộc, sinh nghi vì số lượng địch đông bất thường và cảnh giác né tránh một con Ngư Long trong hồ. Ở con đường khác, song kiệt Vũ tộc canh giữ thông đạo bàn về Thạch Nghị đang xông Thượng Cổ cấm địa tìm Thiên Cốt cùng khả năng Trùng Đồng, khi một cường giả cháy đen chạy tới báo tin người của họ đã bị giết sạch. Nhóc tỳ cưỡi Sư Tử chín đầu như thần nhân hạ giới, đánh gục thêm mười tám thiên tài rồi dùng bảo kính Toan Nghê giết chết kẻ truyền tin ngay trước mặt bọn Vũ tộc. Cuối cùng, một thiếu nữ chừng mười lăm mười sáu tuổi thuộc song kiệt Vũ tộc đứng dậy trước thông đạo, Phù Văn lấp lóe đầy trời, hé mở trận đối đầu sắp tới."},{"chuong":128,"tieuDe":"Thông Linh","tomTat":"Vũ Tử Mạch, thiếu nữ tà áo xanh của Vũ tộc và là một trong 'song kiệt' cùng Thạch Nghị, sở hữu Thông Linh Thần Giác nhưng không thể nhìn thấu nhóc tỳ vì bị sương mù bao phủ, giống hệt trường hợp Thạch Nghị. Phụng lệnh trưởng bối vào Bách Đoạn sơn truy giết kẻ đã hạ mười tám cao thủ Vũ tộc, nàng thi triển Bảo Thuật Thông Linh 'Nhất Thế Họa Quyển', dùng ký tự dệt sách cổ Phù Văn gần như bất hủ để phong ấn đối thủ. Nhóc tỳ ngồi trên Sư Tử chín đầu phản kích bằng cối xay bạc phá vỡ quyển sách cổ, khiến bảo thuật của nàng mất hiệu lực. Vũ Tử Mạch chuyển sang hóa mưa thành binh và triển khai 'Trong mưa sinh điện', tia chớp xanh đánh nát một tòa núi nhỏ thành bốn mảnh. Tuy nhiên nhóc tỳ tinh thông lôi điện, dùng bảo kính Toan Nghê khắc chế công pháp Vũ tộc, đánh nàng ho ra máu và lần lượt hủy Bảo Tán, Bảo Y lông chim tím của nàng. Cùng đường, Vũ Tử Mạch tái triển Thông Linh dệt bức tranh nhiều màu phòng ngự, Phù Văn tạm chặn được lôi đình thần uy. Nhóc tỳ liền buông lời khiêu khích thân hình khiến nàng nổi giận run bần bật, Phù Văn lay động bất ổn, rồi thúc giục Toan Nghê phóng lôi đình cùng điện vàng đánh thẳng tới."},{"chuong":129,"tieuDe":"Người Phong Ấn","tomTat":"Nhóc tỳ ở Hư Thần giới điên cuồng oanh kích Vũ Tử Mạch, đánh tan Phù Văn cuối cùng và làm gãy hai cánh tay nàng khiến đòn cuối bảo thuật Thông Linh thất bại, buộc thiếu nữ thiên tài Vũ tộc phun máu bại trận; nàng kinh hãi nhận ra thân thể cuồng bạo của nhóc tỳ giống với Thạch Nghị vài năm trước. Ngay khi nhóc tỳ chuẩn bị đòn giết cuối, bốn siêu cấp cường giả Vũ tộc xuất hiện ở bốn hướng vây bắt nó cùng Sư Tử chín đầu; qua bàn tay đầy nếp nhăn, nhóc tỳ vạch trần chúng là Người phong ấn — kẻ tự phong ấn thực lực để vượt cấm chế tuổi tác của Bách Đoạn sơn, tiểu thế giới bài xích người quá mạnh. Hai bên giả liều mạng rồi bất ngờ dùng Bảo Cụ dưới chân phóng lên trời bỏ chạy, nhóc tỳ biến Sư Tử chín đầu thành khiên thịt che sau, cả bọn vừa trốn vừa chiến đều bị thương nặng. Sư Tử chín đầu bị màn mưa thần lực bắn thủng ngực phải như cái sàng, nhóc tỳ cũng ho ra máu nhưng nhờ thân thể sánh Thiên giai Thái Cổ hung thú con nên trụ được. Trong tuyệt cảnh, nhóc tỳ quát 'Đi!' chủ động chặn bốn đại cường giả để mở đường sống cho Sư Tử chín đầu, khiến nó cảm động hứa xóa món nợ cũ với Cửu Linh Vương rồi phóng hào quang hoàng kim biến mất cuối chân trời. Bốn cường giả thu mưa lộ chân thân gồm hai lão già và hai trung niên, nhận ra chân mày lúc nhóc tỳ nổi giận giống hệt Thạch Tử Lăng năm xưa và gọi nó là 'tiểu nghiệt súc năm đó'. Trung niên Vũ Côn lộ danh tính, kể lại thúc tổ mình từng đuổi Thạch Tử Lăng từ Hoàng Đô tới Tây Cương, dùng Cốt Tiễn xuyên thủng lá phổi suýt trúng tim, rồi chằm chằm muốn nhìn rõ mặt nhóc tỳ."},{"chuong":130,"tieuDe":"Vô Đề","tomTat":"Bốn cường giả Vũ tộc quyết truy sát nhóc tỳ vì nghi ngờ nó chính là đứa bé sắp chết năm xưa, kẻ dù mất Chí Tôn Cốt vẫn quật khởi với thiên tư đáng sợ, nên muốn tốc chiến diệt trừ trước khi Võ Vương phủ hay biết. Nhóc tỳ dùng cây quạt bạc phù cốt nạp lực sấm sét từ bảo kính Toan Nghê rồi ném nổ tung phản kích, tuy không giết được ai nhưng thoát thân dù thân thể đầy thương tích lộ cả xương. Nó cố ý giả ngã bên bờ hồ lớn, giấu bảo kính nhắm mặt nước, chờ bốn kẻ địch xông tới liền oanh tia sấm chớp khuấy động hồ, dụ con Ngư Long khổng lồ trồi lên nuốt chết một cường giả và cắn tàn phế một kẻ khác. Hai kẻ còn lại vác đồng bọn mất hai chân bỏ chạy rồi điều động Bảo Cụ tiếp tục truy sát, không dám liều với Ngư Long vì sợ pháp tắc tiểu thế giới. Trên đường trốn, nhóc tỳ suýt đụng Hỏa Vân Tước Đại Hồng — con ác điểu từng bị nó 'mượn' hai mươi cân thịt nên khiếp sợ gọi nó là Ma Vương; nó đánh gục và ôm chặt cổ Đại Hồng để cưỡi thoát thân. Đại Hồng định phản kháng bay ngược về phía truy binh mong có người thu phục Ma Vương, nhưng bị nhóc tỳ dọa 'xin thịt' liền rụt cổ quay đầu hóa áng lửa xẹt qua tầng mây. Hai cao thủ Vũ tộc sắp đuổi kịp thì con mồi bỗng biến thành kỵ sĩ chim bay mất, tức đến đau khắp người."},{"chuong":131,"tieuDe":"Lông Chim Mù Trời","tomTat":"Vũ Côn và Vũ Văn đuổi theo Thạch Hạo đến kiệt sức nhưng nó cưỡi Đại Hồng Điểu (Hỏa Vân Tước) bay mất trong sương mù, đành từ bỏ và quyết giết nhóc tỳ khi có cơ hội. Thạch Hạo khống chế Đại Hồng Điểu làm phương tiện bằng cách dọa ăn thịt, gõ đầu và vặt lông, buộc nó dẫn đến sào huyệt Tọa Sơn Điêu — nơi có tổ chim khổng lồ với gò xương hài cốt nhân loại và ba quả trứng lớn lót trong Ngân Lũ Thảo. Đại Hồng Điểu cắt trứng bằng lông vũ rồi phun lửa nướng chín; Thạch Hạo ăn cả ba quả, vận chuyển phù văn luyện hóa tinh khí thần chữa lành toàn bộ vết thương, thể phách mạnh hơn và tròng mắt trong suốt hơn. Khi Tọa Sơn Điêu về tổ điên cuồng công kích, Đại Hồng Điểu phản kích và đánh đuổi được đối thủ nhưng bị thương thảm hại. Mặt khác, Vũ tộc truy tìm Thái Nhất Chân Thủy — thần dịch trân quý một giọt giá trị liên thành, có thể khiến tộc quật khởi và xuất hiện Nhân Hoàng — Vũ Côn xác định ao nước trước mặt chính là hồ Thái Nhất Chân Thủy nhưng nơi này xuất hiện ảo cảnh vừa lừa dối vừa kêu gọi tiến gần, hai ngày qua Vũ tộc không thể tiếp cận."},{"chuong":132,"tieuDe":"Tài Cao Chót Vót","tomTat":"Đại Hồng Điểu bay nhiều ngày mệt rũ đòi bãi công, bị Thạch Hạo nhổ lông rồi dùng Cốt Tiễn vàng kim hiện bản thể đầu rồng cắn cổ chảy máu ép tiếp tục truy tìm Vũ tộc. Thạch Hạo lấy lông thần Tiểu Hồng Điểu tỏa thần uy Chí Tôn khiến Đại Hồng Điểu run sợ, lật mặt quỳ xin làm đồ đệ, rồi hăng hái tìm được tin Vũ tộc đã vào sa mạc tìm chí bảo. Hai bên tiến vào sa mạc vàng kim, phát hiện bảo dược Sa Mạc Ngân nhưng thiếu niên áo bạc Tiêu Thiên đã hái trước và chém chết mấy con bò cạp bạc. Khi bò cạp bạc ẩn trong cát chui ra phục kích, Thạch Hạo dùng Cốt Tiễn cứu Tiêu Thiên, đồng lúc Tiêu Thiên đột phá mở được Động Thiên thứ tám. Qua chuyện cùng ghét bốn chữ tài cao chót vót, Tiêu Thiên xem Thạch Hạo là tri kỷ mà không biết đây chính là kẻ từng đánh trộm mình. Tiêu Thiên tiết lộ mục tiêu Thánh Vật Thái Nhất Chân Thủy và thổ lộ căm ghét đại địch đầu gấu vạn ác — chính là Thạch Hạo đang giả vờ kết giao bên cạnh; hai người quàng vai đồng hành lặng lẽ đi sâu vào sa mạc."},{"chuong":133,"tieuDe":"Thái Nhất Chân Thủy","tomTat":"Trong một mảnh sa mạc nóng như lò lửa của Bách Đoạn sơn, Vũ tộc tiến gần Thần trì chứa Thái Nhất Chân Thủy — dị bảo vô giá đã thông linh, diễn hóa phù văn pháp tắc và triệu hoán hơn mười bộ hài cốt cường giả để chống lại. Vũ Văn Thành, Vũ Côn dùng nước Hoàng Tuyền phá tan toàn bộ hài cốt, nhưng một gốc linh đằng thủ hộ trồi ra hủy vỡ túi càn khôn phỏng chế của Vũ Côn khiến lão phun máu gãy xương bại trận. Vũ tộc lập tế đàn, đốt giấy vàng hiện pháp chỉ truyền miệng của Vũ thần cùng di vật tổ tiên để chứng thực là hậu duệ, khiến nước thần nguyện đi theo. Nhóc Tỳ, Đại Hồng Điểu và Tiêu Thiên ẩn nấp quan sát; Tiêu Thiên tiếc nuối vì Vũ tộc đến trước, giải thích về túi càn khôn Thượng Cổ. Khi Vũ tộc trang trọng thu Thái Nhất Chân Thủy vào đỉnh ngọc mơ tưởng lập quốc, Nhóc Tỳ tự nguyện xông vào, mượn lực bật từ quy thuẫn của Tiêu Thiên vọt ngang như sao băng. Sức bật kinh khủng đánh bay Tiêu Thiên năm sáu dặm làm quy thuẫn vỡ vụn, còn Nhóc Tỳ nhào vào Bảo Cụ đỉnh ngọc quẫy nước rầm rầm và nuốt từng ngụm lớn Thái Nhất Chân Thủy, khiến Vũ tộc choáng váng đông cứng ngỡ là ảo giác."},{"chuong":134,"tieuDe":"Uống Sạch","tomTat":"Nhóc Tỳ từ trên trời đập xuống ngay giữa Thái Nhất Chân Thủy của Vũ tộc, vùng vẫy trong nước thần mà uống thẳng vào bụng, phá tan kế hoạch luyện bảo cụ của bộ tộc. Vũ tộc chia hai phe — kẻ muốn giết ngay, kẻ muốn cướp phần chân thủy trước — trong khi Nhóc Tỳ dùng Định Quang Châu tạo màn sáng hình cầu ngăn phù văn và tạm giữ nước thần, khiến Vũ Văn Thành nhận ra đó là mảnh vỡ thời thượng cổ. Thái Nhất Chân Thủy có linh, thành tinh chui ra từ thất khiếu và lỗ chân lông, buộc Nhóc Tỳ vận Nguyên Thủy Chân Giải bịt kín để tiếp tục uống. Khi Định Quang Châu mờ dần, Nhóc Tỳ đổ đầy một bình ngọc, bỏ Định Quang Châu vào rồi dùng Cốt Tiễn cắt đứt đỉnh ngọc; phần chân thủy còn lại hóa sương mù vàng trốn vào lòng đất cùng linh đằng. Đại Hồng Điểu bay đến đón Nhóc Tỳ khỏi vòng vây, Nhóc Tỳ nhổ lông lấy máu chim vẽ lên mặt che giấu mặt thật. Ba người hội quân, chạy vào núi nguyên thủy đáp xuống một ngọn Linh sơn, Tiêu Thiên kích động ôm bình ngọc còn Nhóc Tỳ ngồi luyện hóa nhưng nước thần cứ phun ra đằng miệng."},{"chuong":135,"tieuDe":"Khí Tức Của Chí Tôn","tomTat":"Trên Linh sơn, Nhóc Tỳ ngồi xếp bằng cố luyện hóa Thái Nhất Chân Thủy, cả người phát sáng dù đã bịt kín lỗ chân lông. Đại Hồng Điểu tiếc rẻ thánh vật bị phung phí nên phun ra một nồi đen (trứng chim mài giũa) có phù văn lôi điện để hấp thu nước thần, còn Tiêu Thiên cảnh báo uống nhiều sẽ bị nước thần luyện hóa ngược. Thái Nhất Chân Thủy có linh tính liền tụ lại phản luyện hóa, trùng kích mãnh liệt khiến xương cốt Nhóc Tỳ rung răng rắc, suýt nổ tan xác nhưng nhờ thân thể sánh con non hung thú Thái Cổ thiên giai mới trụ được. Đúng lúc nguy cấp, ngực nó nóng bừng hào quang, thiên địa thất sắc, nước thần bị ép thành mặt trời nhỏ chứa hình vị Chí Tôn thai nghén — mầm Chí Tôn Cốt mới hình thành. Nhóc Tỳ nhận ra khí tức Chí Tôn Cốt quen thuộc từ bé; chương hé lộ nó vốn là con cháu dòng chính Võ Vương phủ, bảo cốt và tinh huyết cũ bị cướp đoạt đã bắt rễ trong Thạch Nghị. Sau khi nước thần được hấp thu hoàn toàn, Nhóc Tỳ đột phá khai mở Động Thiên thứ tám không dấu hiệu báo trước, khiến Tiêu Thiên và Đại Hồng Điểu bàn luận về khả năng mở cả Động Thiên thứ chín truyền thuyết."},{"chuong":136,"tieuDe":"Đồng Lõa","tomTat":"Sau khi được Thái Nhất Chân Thủy tẩy lễ, thân thể Nhóc Tỳ tăng cường một bậc: ngũ tạng vang như trống trời, cốt cách trong suốt như ngọc. Nó thị uy sức lực bằng cách nhảy từ đỉnh núi làm vỡ hố sâu và một tay nhấc tảng đá ba bốn chục vạn cân, khiến Tiêu Thiên và Đại Hồng Điểu kinh sợ. Tiêu Thiên cảm thấy Nhóc Tỳ giống thằng nhỏ đầu gấu ở Hư Thần Giới nhưng tự trấn an vì nghĩ nếu đúng thì nó đã cướp nước thần chạy mất. Nhóc Tỳ định cùng Đại Hồng Điểu cướp Thái Nhất Chân Thủy của Tiêu Thiên, nhưng khi động thủ lại quay sang đập cục đá vào ót Đại Hồng Điểu rồi đổ tội cho nó định đánh lén. Tiêu Thiên tin lời, trách Đại Hồng Điểu; Đại Hồng Điểu uất ức hộc máu nhưng vì cần được giới thiệu sư phụ nên không dám vạch mặt. Cuối cùng Tiêu Thiên và Nhóc Tỳ chia chác nước thần, gạt Đại Hồng Điểu ra ngoài rồi khích nó bằng lối chơi chữ, khiến nó đành bụm lỗ mũi chở hai người bay đi tìm Vũ tộc."},{"chuong":137,"tieuDe":"Chương 137: Đại Thắng","tomTat":"Đại Hồng Điểu bay ngang dãy núi bị Bạo Viên cùng hung thú bắt nạt, phải hóa lửa bỏ chạy dù tự xưng đời sau thần điểu Chu Tước. Nhóc Tỳ cùng Tiêu Thiên và Đại Hồng Điểu vào sa mạc tìm Vũ tộc và Thái Nhất Chân Thủy, phát hiện Vũ Văn Thiên đã tàn phế đang chờ Thạch Nghị tới dùng Song đồng phá hư không. Nhóc Tỳ chủ động xuất hiện, dùng thần lực thiên phú kết hợp phù văn đánh Vũ Văn Thiên phun máu gãy cánh tay, rồi dùng bảo kính Toan Nghê và Cốt Tiễn màu vàng phá và cắt đứt sừng thú đen. Tiêu Thiên vây chặn còn Đại Hồng Điểu mang nồi đen tàn sát đám đệ tử Vũ tộc. Vũ Văn Thiên ngồi Linh Vũ định trốn thì bị Cốt Tiễn kẹp đứt rồi bị Nhóc Tỳ chém rụng đầu, chết trong uất ức. Toàn bộ Vũ tộc tiến vào Bách Đoạn sơn bị diệt sạch, chỉ còn Vũ Côn, Vũ Văn Thành và Vũ Tử Mạch sống sót. Sau chiến thắng Nhóc Tỳ qua thông đạo màu vàng vào thiên địa mới, bị người Võ Vương phủ đang săn di chủng quát đuổi và giật mình nhận ra đây chính là nơi mình ra đời nhưng năm xưa đã bị bỏ rơi."},{"chuong":138,"tieuDe":"Con Cháu Võ Vương Phủ","tomTat":"Một con Tử Điêu Thái Cổ di chủng tím óng dài một trượng, trán có mắt dọc, đang bị trọng thương thì bị nhóm thiếu niên Võ Vương phủ vây bắt. Nhóc Tỳ nhảy xuống ngăn cản, hồi tưởng việc mình mất Chí Tôn cốt và tám năm bị bỏ rơi chỉ còn a Man làm bạn, rồi động thủ vỗ tan phù văn, đánh tan giao long và vuốt giao, tay không đoạt tấm da giao thú và quần công cả đám thành đầu heo. Nhóc Tỳ chất họ thành đống ngồi lên hỏi “đã phục chưa”, Đại Hồng Điểu nhảy nhót cầm nồi đen đập làm nhục, đám thiếu niên xấu hổ rút lui đi tìm Tứ ca, Lục ca, Cửu đệ và Thạch Nghị đường đệ trong cấm địa. Con Tử Điêu biết ơn tiết lộ có một khu di tích chứa đầy bảo cụ thông linh như Kiếm sơn, sừng thú, Thần hoàn, và kể mình trốn ra từ một cấm địa quý giá nhất Bách Đoạn sơn. Cả nhóm cùng nhau xuyên qua thông đạo màu vàng, vượt hai mươi bốn khu vực đầy trận chiến để tiến vào trung tâm hoang vu như ma thổ, nơi vô số sinh linh cường đại của các gia tộc cổ, Tịnh thổ và Vương tộc Cổ quốc đang do dự trước cửa di tích."},{"chuong":139,"tieuDe":"Chương 139","tomTat":"Trước một sơn môn tráng lệ tụ tập vô số Thái Cổ di chủng huyền thoại: Thổ Hành Long dài năm mươi mét, Bạo Viên đen, Liệt Thiên Ma điệp có thể nứt vỡ vạn dặm trời xanh, bầy Kiến Thần mười hai con, Bồ Ma thụ hút thần tinh, và Tất Phương Ma cầm Thiên giai từng ăn thịt Thần linh. Nhóc Tỳ hoành hành giữa đám di chủng, đẩy cường giả sang hai bên, một cước đánh gãy xương hàm một hung thú khiến cả đám hoảng sợ. Gặp lại Sư Tử chín đầu (Hoàng Kim sư tử, hậu đại Thái Cổ Thần vương), Nhóc Tỳ tiết lộ đã giết hai trong bốn lão già truy sát trước đó và ép nó nhận làm tiểu đệ giữa đông đảo di chủng khiến nó mất mặt. Hai cường giả Tộc ba mắt anh em ruột và chim Loan năm màu xuất hiện; chim Loan trêu chọc chín đầu và đòi làm thịt thiếu niên Nhân tộc. Nhóc Tỳ tiến lên chỉ mặt cả hai cường giả bảo tránh ra, dọa chim Loan chọn nướng hoặc luộc, không thèm để ai vào mắt, khiến cả sơn môn náo động ầm ĩ."},{"chuong":140,"tieuDe":"Giương Cao Hung Uy Của Nhân Tộc","tomTat":"Nhóc Tỳ đối đầu chim Loan năm màu (hậu duệ Thần điểu), coi nó chỉ là món ăn; chim Loan bắn lông vũ hóa mũi tên nhưng bị Sư Tử chín đầu chặn lại vì tổ phụ chim Loan có giao tình với Cửu Linh Vương. Các di chủng vây lại: hai huynh đệ Tộc ba mắt chế nhạo, Phì Di (Thái Cổ di chủng cựu thù từ Đoạn Không thành) và Quạ Lửa cùng góp mặt ngoài sơn môn nguy nga. Nhóc Tỳ sai Đại Hồng rửa nồi đen đun nước sôi mở tiệc hầm di chủng, rồi đánh bại hai huynh đệ Tộc ba mắt bằng cách nắm mắt cá chân nện xuống đất và dùng tù binh chắn đòn phản kích. Trong đại chiến, Nhóc Tỳ vận toàn bộ bảo cụ: bảo kính Toan Nghê phóng sấm sét, đối phó Bảo Phiến năm màu của chim Loan và phi kiếm răng nanh Hỏa đạo của Phì Di. Nó dùng Thần nguyệt cùng bảo kính áp chế, đoạt phi kiếm đỏ của Phì Di, phát Long Giao tiễn suýt cắt đôi rồi bảo kính sấm sét đánh gục Phì Di. Cốt Tiễn màu vàng chặt đứt hơn mười cân huyết nhục cẳng chân và đục lỗ cánh thần chim Loan; bốn đại cường giả đều thất bại trong thời gian ngắn. Nhóc Tỳ lấy thịt chim Loan, xách Phì Di lên vai làm tiệc, mời Sư Tử chín đầu; khi rửa mặt bên suối, thân phận nhóc siêu quậy ở Hư Thần giới bị lộ khiến các thiên tài Toan Nghê, Li Long, Tỳ Hưu, Tất Phương khiếp sợ mà không dám động thủ."},{"chuong":141,"tieuDe":"Ăn Như Gió Cuốn","tomTat":"Nhóc Tỳ tiến vào tiểu thế giới Bách Đoạn sơn, lập tức gây chấn động thiên tài các tộc bởi cái danh nhóc siêu quậy từ Hư Thần giới mà nhiều thế lực từng treo giải lấy đầu. Bên dòng suối cạnh sơn môn, Đại Hồng Điểu hầm canh rắn Phì Di còn Nhóc Tỳ nướng thịt chim Loan năm màu, ăn ngấu nghiến trước mặt cả đám Thái Cổ di chủng thèm thuồng mà tức tối; nó cùng Tử Điêu và Đại Hồng Điểu nuốt túi mật rắn để bồi bổ đột phá. Nhờ mật Thái Cổ di xà và hơn nửa con Phì Di, Đại Hồng Điểu tắm lửa thăng cấp, thực lực tăng vọt, còn Tử Điêu lành thương suýt đột phá; riêng Nhóc Tỳ dù được gột rửa thân thể vẫn chưa mở nổi Động Thiên thứ chín. Sư Tử chín đầu khó xử không dám ăn vì chim Loan là họ hàng nhiều đời, còn chim Loan tức giận bay lượn trên trời nhưng không dám lao xuống quyết chiến. Ăn no, Nhóc Tỳ trị thương và kết giao với các di chủng quen biết Sư Tử chín đầu, đồng thời không hay biết bốn đại cường tộc từng bị nó làm nhục ở Hư Thần giới đã cử người tới báo thù, có kẻ muốn bắt sống nó để đoạt lại bảo phiến Xích Vũ. Bất chấp lời cảnh báo về bảo cụ thông linh tự chém giết người tiếp cận, Nhóc Tỳ kêu gọi cả đoàn xông vào Thượng Cổ phế tích săn bảo. Nhiều sinh linh khủng bố như Tất Phương, Tỳ Hưu, Li Long cũng đồng loạt tiến vào, báo hiệu sát kiếp sắp nổi."},{"chuong":142,"tieuDe":"Thần Triều","tomTat":"Nhóc Tỳ dẫn đoàn Thái Cổ di chủng tiến vào khu phế tích Thượng Cổ trong Bách Đoạn sơn, nơi cất giấu vô số bảo cụ thông linh biết di chuyển. Bị một Người phong ấn áo bào xanh của một trong bốn đại gia tộc từng bị nó vơ vét chém lén, Nhóc Tỳ dùng bảo kính Toan Nghê đánh nứt xương bả vai đối phương, buộc hắn phải dùng Súc Địa phù trốn thoát. Trong hai ngày, nó trở thành cường hào càn quét phế tích, truy sát ngược lại các cường giả Nhân tộc âm mưu hại mình. Bất ngờ Thần triều nổi lên: vô số bảo cụ Thái Cổ thức tỉnh tàn sát điên cuồng, giết hơn hai ngàn thiên tài, khiến Nhóc Tỳ đành bỏ chạy dù thấy nhiều dị bảo quý giá. Sống sót và tách khỏi nhóm, nó đi sâu vào phế tích, tìm ra quy luật Thần triều và ngọn nguồn ở vùng núi bên trong. Sau khi thoát khỏi một cuộc phục kích của năm Người phong ấn bằng cách dẫm sụp cả ngọn núi, Nhóc Tỳ phát hiện một cốt tháp thần thánh trắng toát và ra tay trấn áp để đoạt lấy. Đúng lúc đó, một con Bạch Hổ ngồi trên xe kéo bảo cụ kéo tới, nhận ra nó từ Đoạn Không thành và tuyên bố cốt tháp đã thuộc về mình."},{"chuong":143,"tieuDe":"Chí Bảo Trong Di Tích","tomTat":"Nhóc Tỳ tranh đoạt tòa cốt tháp trắng tinh lơ lửng trong khe núi di tích thì bị con Bạch Hổ Thái Cổ di chủng biết nói tiếng người dẫn lão già cùng đám thủ hạ tới quấy phá và ra lệnh giết hắn. Bị quấy nhiễu nhiều lần, cốt tháp thức tỉnh thành tinh, bùng nổ ánh sáng như sao băng hủy diệt cả vùng núi, bắn xuyên vai Bạch Hổ và ngực lão già khiến chúng tháo chạy, rồi tự hóa cầu vồng lao vào biển lửa Địa Hoàng Hỏa để tế luyện lột xác. Nhóc Tỳ cưỡi bảo kính Toan Nghê đuổi theo, đồng thời để mắt thèm muốn chiếc túi Càn Khôn làm từ da Thái Cổ di chủng có thể chứa vạn vật. Chưa kịp lấy tháp, hắn bị thanh niên áo bào xanh dẫn gần hai mươi người Côn tộc — bại tướng bốn đại gia tộc từng bị hắn chất thành đống người ở Hư Thần giới — tới vây giết, khiến hắn ứa máu vì thua kém phù văn. Nhóc Tỳ dụ địch vào dãy núi dung nham, vung bảo kính kích động cốt tháp nổi giận đánh vỡ bảo cụ Côn tộc khiến chúng rơi xuống dung nham chết, rồi dùng Cốt Tiễn màu vàng chờ trước cắt đôi hai kẻ trốn thoát. Hơn một tháng trong di tích trôi qua, dung nham lắng lại, cốt tháp hút sạch địa hỏa co lại thành tiểu tháp trắng như ngọc, không phản ứng gì nên hắn đành quấn lên tóc làm trang sức. Khi tới Phân Bảo Nhai — ngọn nguồn di tích nơi nhiều thiên tài tụ tập, tiếng già nua của Quỷ gia bỗng vang bên tai đòi 'kiếm của ta', khiến hắn kinh ngạc vì Quỷ gia đáng lẽ ở lại Bổ Thiên các."},{"chuong":144,"tieuDe":"Phân Bảo Nhai","tomTat":"Nhóc Tỳ chiếu bảo kính Toan Nghê phát hiện chuỗi ký tự đen nguyền rủa của Bổ Thiên các trên trán, buộc phải tìm một thanh kiếm gãy nếu không sẽ chết. Nó lên Phân Bảo Nhai — ngọn núi đầy hài cốt thiên tài cổ đại — đối đầu các thiên tài dị tộc như Tất Phương, Tỳ Hưu, Bạo Viên và chim thần màu vàng. Nhóc Tỳ đánh bại cây thực vật kỳ lạ bằng tia chớp vàng, đoạt chiến mâu; bảo cụ Cánh Kim Ô xuất thế bị chim thần màu vàng cướp đi. Nó chinh chiến giết sạch hai ba mươi thiên tài ba tộc Ly-Uyên-Mông bằng Long Giao tiễn rồi leo lên đỉnh vùng ngừng chiến. Tại rừng đá, Tất Phương đoạt được pháp trượng đỏ như máu; kẻ tranh đoạt bừa bị Phân Bảo Nhai đánh thành thịt nát. Người phong ấn ba tộc và Bạch Hổ hẹn giết Nhóc Tỳ khi rời khỏi, nó ngạo nghễ nhổ nước bọt đáp trả."},{"chuong":145,"tieuDe":"Kiếm Cổ","tomTat":"Trong rừng đá Thượng Cổ đầy đồ án Kim Ô trục điện, Tù Ngưu vượt biển, Côn Bằng giương cánh, Nhóc Tỳ dùng phù văn Nguyên Thủy Chân Giải câu thông tìm bảo cụ nhưng vô dụng. Nó đi trêu chọc đám Người phong ấn đã bị nó giết con cháu và con Bạo Viên đen thui, khiến họ tức hộc máu nhưng không dám động thủ vì đây là nơi ngừng chiến. Nghe văng vẳng “Kiếm của ta…”, tảng đá dưới chân nứt vỡ lộ ra Kiếm Cổ — đoạn sắt gãy rỉ sét nặng mấy vạn cân mang đại sát khí chư thánh. Khi rút kiếm, sát khí ngập trời xâm nhập suýt xoắn nát thân, tiểu tháp trên tóc đột nhiên sáng lên xua tan toàn bộ. Bạch Hổ giải thích về hắc sát chiến trường cổ. Cuối chương công chúa Hỏa quốc Hỏa Linh Nhi dẫn nhóm người vào rừng đá; Nhóc Tỳ gọi nàng là “sư muội” và tuyên bố bảo kê."},{"chuong":146,"tieuDe":"Chương 146","tomTat":"Công chúa Hỏa quốc xinh đẹp đi cạnh Nhóc Tỳ khiến nhiều người khó chịu; nhóm Người phong ấn bàn nhau bằng mọi giá diệt Nhóc Tỳ trước khi hắn về Bổ Thiên các. Nhóc Tỳ dẫn Hỏa Linh Nhi cùng các sư huynh sư tỷ đi trêu chọc đám Người phong ấn, kể đã giết cháu/hậu bối của họ. Một tảng đá lớn nứt ra lộ Cốt hoàn Thượng Cổ màu xanh da trời thiếu một miếng, Hỏa Linh Nhi giành đeo lên tay dù sói con muốn tháo cho Nhóc Tỳ. Đại Hồng Điểu đầy máu bay tới báo Sư Tử chín đầu và Tử Điêu sắp bị phân thây, Nhóc Tỳ nhờ Hỏa Linh Nhi dùng thủ hạ Người phong ấn giúp việc rồi cưỡi chim bay đi. Tại chiến trường bên chân núi Phân Bảo Nhai, đám Thái Cổ di chủng của Nhóc Tỳ bị đánh trọng thương; nó đối đầu Bạch Hổ, Bạo Viên và chim thần màu vàng, hỏi chim thần có mang huyết thống thuần huyết Thái Cổ thần sơn không."},{"chuong":147,"tieuDe":"Chương 147","tomTat":"Con chim thần màu vàng ra mặt với mắt như vòng xoáy nuốt linh hồn khiến Đại Hồng Điểu choáng váng. Bạo Viên nắm Kim Cương thần lực nôn nóng xông lên đánh Nhóc Tỳ trước; Nhóc Tỳ phản đòn bằng sấm sét bảo kính Toan Nghê phá màn sáng chân Bạo Viên rồi dùng Cốt Tiễn màu vàng chém máu văng. Bạo Viên kích hoạt phù văn Kim Cương phình to ba mươi mét tung sóng trùng kích, nhưng Nhóc Tỳ dùng phù văn Nguyên Thủy Chân Giải với trăng bạc bao phủ, đấm thủng máu thịt Bạo Viên và đánh nổ chuông đen của nó. Nhóc Tỳ nhấc Bạo Viên đập trái đập phải như xách người rơm, khiến nó teo nhỏ. Khi bầy Thái Cổ di chủng vây công, Nhóc Tỳ cắt đôi một mãnh thú và thiêu một hung cầm, nhưng lưng bị Bạch Hổ lén xé tận xương. Nổi giận, Nhóc Tỳ nghiền nát Bạo Viên rồi tiến đánh Bạch Hổ; Bạch Hổ hóa luồng sáng trắng tham chiến."},{"chuong":148,"tieuDe":"Kiếm Gãy Chém Bát Phương","tomTat":"Bạch Hổ (Thái Cổ di chủng thuộc tính kim, cảnh giới ngang Người phong ấn) áp đảo Nhóc Tỳ bằng tốc độ và sức mạnh, phun khí kim loại hóa giải tia chớp. Nó tế ra 28 chiến mâu trắng bạc do răng nanh hóa thành vây đâm, mặc bảo y Bạch Hổ phòng ngự cực mạnh; Long Giao tiễn của Nhóc Tỳ phá được bảo y khiến Bạch Hổ chảy máu. Bạch Hổ lấy túi Càn Khôn hút vạn vật định đoạt binh khí, buộc Nhóc Tỳ rút Kiếm Cổ — một nhát chém đứt toàn bộ 28 chiến mâu, phá bảo ấn nổ tung. Nhóc Tỳ chém đứt nửa thân Bạch Hổ, sai Đại Hồng tiếp lấy máu thịt đại bổ, rồi đoạt túi Càn Khôn, mưu tính bắt hết Thái Cổ di chủng trong Bách Đoạn sơn nhét vào. Cuối chương chim khổng lồ màu vàng xuất trận như Thần vương, ra lệnh mười mấy di chủng giết Nhóc Tỳ và tuyên bố sẽ cướp kiếm gãy."},{"chuong":149,"tieuDe":"Kim Sí Bằng Điểu","tomTat":"Khi Bạch Hổ chỉ còn nửa thân thể cầu cứu, con chim khổng lồ màu vàng lạnh nhạt bỏ mặc, để mặc Nhóc Tỳ vung kiếm gãy chém đứt đầu hắn; trước khi chết Bạch Hổ tự hủy nguyên thủy phù cốt khiến Nhóc Tỳ tiếc nuối, còn thân thể thì ném cho Đại Hồng ăn bổ. Nhóc Tỳ nhục mạ chim vàng là 'con gà con', khiến cả đám Thái Cổ di chủng sững sờ trước sự xúc phạm một Kim Sí Đại Bằng. Chim vàng ra lệnh giết, hơn mười di chủng cùng xông tới nhưng bị kiếm khí của Nhóc Tỳ phá tan, một tên nổ tung thành sương máu. Kim Sí Bằng điểu phun ra Nguyên Từ Phong khắc chế binh khí kim loại, nhưng kiếm gãy pháp khí Thượng Cổ vẫn thoát khỏi trói buộc, hai bảo cụ đỉnh cấp giao chiến kinh thiên. Sư Tử chín đầu tiết lộ chim vàng là bán huyết Kim Bằng, cảnh giới cao hơn Nhóc Tỳ, và nó lại tung ra bảo phiến vàng tế luyện từ cánh Kim Ô, thần hỏa ngập trời hóa mặt đất thành dung nham. Sau va chạm đầu tiên cả hai đều trọng thương, kiếm gãy tróc rỉ sét lộ thân kiếm đen thui khiến Bằng điểu khiếp sợ vì uy năng tăng dần, và nó nhận ra Nhóc Tỳ nãy giờ giả ngốc với thân thể mạnh ngang thần thú thuần huyết. Bằng điểu dùng đòn hút hồn hai mắt xoáy vàng nhưng bị Nhóc Tỳ phun tinh khí chí cương chí dương kèm tia chớp phá giải, rồi tung cú đá chặn cánh thần sắc hơn thiên đao khiến cả hai bay ngược ra, mở đường cho đợt lao xuống móng vuốt tiếp theo."},{"chuong":150,"tieuDe":"Anh Dũng Phục Bằng","tomTat":"Nhóc Tỳ đứng trên bảo kính Toan Nghê quyết chiến sinh tử với Kim Sí Bằng điểu, đấu cả về phù văn lẫn thân thể qua hơn tám trăm hiệp, ngang sức bất phân thắng bại. Nó dùng cối xay màu bạc nghiền ép mưa lông vàng, kết hợp trăng bạc và sấm sét chồng chất bảo thuật, dùng Thanh Thiên Bằng chụp nát thần kiếm vàng của đối thủ. Có lúc bị móng vuốt suýt xé bụng lòi ruột nhưng vận thần hi khép vết thương không để sẹo. Khi Kim Bằng đuối sức, Nhóc Tỳ bùng phát phản công, đánh thủng bụng, cưỡi lưng ôm cổ nện đầu lâu khiến nó phun máu. Kim Bằng gọi hai bảo cụ Nguyên Từ Phong và cánh Kim Ô về nghênh chiến, nhưng đúng lúc thanh kiếm gãy tỉnh giấc tróc rỉ sét khiến uy thế tăng vọt. Cánh Kim Ô cảm nhận điều kỳ lạ bỏ chạy mất, Nhóc Tỳ tự tay phá hủy Nguyên Từ Phong, và tiểu tháp bí ẩn trên tóc âm thầm nuốt năng lượng trận chiến. Cuối cùng Nhóc Tỳ dùng kiếm gãy chém đứt một cánh khổng lồ của Kim Bằng, phân định thắng bại."},{"chuong":151,"tieuDe":"Quét Sạch","tomTat":"Nhóc Tỳ chân đạp bảo kính Toan Nghê chém đứt đầu Kim Sí Đại Bằng (chim thần bán huyết) sau khi nó tự hủy phù cốt để không cho đoạt bảo thuật. Hơn mười ba con Thái Cổ di chủng chia bốn phương tám hướng bỏ chạy, Nhóc Tỳ cùng Sư Tử chín đầu, Đại Hồng Điểu, Tử Điêu và đám thú đuổi giết: Nhóc Tỳ giết bốn con, đám Sư Tử ngăn năm con. Nó thiêu đốt tinh khí thần tăng tốc đuổi giết hung cầm trong mây ép nổ tung, còn Đại Hồng Điểu dùng bảo cụ Hắc Oa giết ác điểu nhưng suýt mất mạng. Hỏa Linh Nhi cùng mấy Người phong ấn bức con hung cầm quay lại để Nhóc Tỳ giết, và kinh ngạc trước việc thiếu niên Nhân tộc giết cả Kim Sí Đại Bằng — Người phong ấn nhận định tiềm lực Nhóc Tỳ so với Nhân Hoàng lúc nhỏ chưa chắc đã kém. Cuối cùng toàn bộ di chủng gồm Kim Sí Đại Bằng và Bạch Hổ đều bị diệt sạch. Người phong ấn khuyên tận dụng máu huyết Kim Sí Đại Bằng làm bảo dược, cả đám tìm suối ninh nấu di chủng bồi bổ. Nhóc Tỳ trêu chọc Hỏa Linh Nhi đòi kết bái với Nhân Hoàng khiến nàng nổi giận."},{"chuong":152,"tieuDe":"Tiến Quân","tomTat":"Sau trận chiến, Hỏa Linh Nhi ngăn không cho ăn Kim Sí Đại Bằng ngay, muốn dùng bài thuốc cổ truyền hầm với bảo dược để phát huy dược hiệu. Đám di chủng xử lý chiến lợi phẩm và ăn thịt Bạo Viên khiến xương gãy liền lại, vết thương khép, Tử Điêu và Sư Tử chín đầu tăng huyết mạch. Nhóc Tỳ đoạt được túi Càn Khôn của bộ tộc Bạch Hổ, tế luyện thành công, thử thu đá mười vạn cân và cả ngọn núi nhỏ, còn hút Đại Hồng Điểu vào túi trêu chọc. Nó bế tắc ở Động Thiên thứ chín, được khuyên tiến đại cảnh giới nhưng muốn ăn thịt Đại Bằng để trùng kích lần nữa. Nhóc Tỳ nấu canh hổ cốt từ chân Bạch Hổ ba canh giờ, dùng bảo thuật làm tan xương, cả đám tranh uống rồi vài con Tử Điêu, Hỏa Nha đột phá bình cảnh. Sáng hôm sau Nhóc Tỳ tuyên bố tìm linh dược, hé lộ Bất Lão Thần Tuyền trong Bách Thảo viên — cấm địa nguy hiểm chỉ Thái Cổ thú non thuần huyết mới dám vào. Đoàn người tiến quân tới gần Bách Thảo viên, Nhóc Tỳ lộ bản chất mê tiền đòi tất cả là của mình."},{"chuong":153,"tieuDe":"Thần Viên","tomTat":"Nhóm Nhóc Tỳ, Hỏa Linh Nhi, Sư Tử chín đầu cùng nhiều Người phong ấn tới gần Bách Thảo viên (Thần viên) khí tức thần thánh. Một sinh linh ba đầu hung tàn thuộc chủ mạch Linh tộc — hậu duệ Thái Cổ vương mạch mạnh nhất — xuất hiện, đang xé xác ăn sống một con Bích Lân Báo rồi tấn công đám người, chặt đứt một tay của Ngũ lão. Nhóc Tỳ quát mọi người lui, một mình đấu chưởng với nó như hai mặt trời nhỏ giao kích, nện quyền làm vỡ xương vai đối phương; sinh linh tàn nhẫn tự giật đứt tay để thoát, xông vào Bách Thảo viên biến mất. Nhóc Tỳ trả lại tay gẫy cho Ngũ lão để nối lại nhờ linh dược, rồi dặn mọi người rời đi, một mình tiến vào Thần viên tìm Bất Lão Thần Tuyền ở trung tâm — nơi phù văn bảo cụ vô dụng, từ trường mạnh vặn vẹo hư không. Nó gặp thần điểu Tất Phương, bị dây leo tím thành tinh tấn công liền nhổ gãy nát, rồi gặp một tảng đá biết nói dính phấn hoa Thông Linh Thần Hoa mở linh trí; Nhóc Tỳ nhấc tảng đá theo, bảo nó kể về Thần viên."},{"chuong":154,"tieuDe":"Vườn Thuốc","tomTat":"Trong Thần viên, Nhóc Tỳ cầm khối Ngoan Thạch biết nói (do Thông Linh Thần Hoa điểm hóa) tra hỏi và biết cây thánh dược này cực hiếm, có thể điểm hóa linh trí và giúp cường giả ngộ đại đạo; nó vốn là bảo dược rơi vào Bất Lão Tuyền chiếm tinh hoa mà đột phá. Ngoan Thạch cho biết Bất Lão Tuyền nằm ở chỗ sâu nhất của vườn linh dược. Nhóc Tỳ ném Ngoan Thạch đập trúng một cường giả Vũ tộc thân người đầu chim cánh tím, giao đấu rồi nhổ trụi lông đối phương sau mười hiệp. Xông qua trường vực thủ hộ, nó thổ huyết ói bốn ngụm máu vẫn ăn tươi chín cây linh dược, đồng thời phát hiện nhiều thi thể sinh linh bị ăn. Một Hoàng Kim thú quát nó hái thuốc cho chủ nhân, Nhóc Tỳ đòi nộp hết thuốc khiến một giọng lạnh chí cường vang lên. Cuối cùng nó phát hiện thánh quang kim sắc chỗ sâu vườn thuốc — chính là Bất Lão Tuyền đang dậy sóng vàng, có nhiều sinh linh vây quanh tranh giành nước thần tuyền."},{"chuong":155,"tieuDe":"Chương 155","tomTat":"Ao Bất Lão Tuyền rộng một trượng vuông tỏa kim quang chói mắt như thái dương, nhiều sinh linh hình người, chim, thú cố tiến lại gần thần trì nhưng bị trường vực kinh khủng cản, còn phải đứng ngoài mấy trượng. Nhóc Tỳ đến kịp lúc, ngồi trên tảng đá xanh tính 'thu thuế'. Bị Hoàng Kim thú — Thần bộc Thái Cổ Thần Sơn — quát đe dọa, Nhóc Tỳ ném ngoan thạch (tảng đá biết nói cực cứng) ba lần trúng, làm chảy máu hốc mắt, gãy cằm rồi gãy sống mũi Hoàng Kim thú, cuối cùng quật nó ngất đi. Ngoan thạch không hề sứt mẻ khiến sinh linh nghi ngờ đây là Đả Thần Thạch trong truyền thuyết. Một thiếu nữ tóc tím khí tức kinh khủng, nghi là hung thú thuần huyết hóa hình người và là chủ nhân của Hoàng Kim thú, cảnh cáo và dọa giết Nhóc Tỳ, còn Nhóc Tỳ lại ngỏ ý muốn hàng phục nàng làm thần thú cưỡi. Cuối cùng Nhóc Tỳ đoạt túi da chứa hai ba chục gốc bảo dược, ngồi chờ thiếu nữ tóc tím lấy được Bất Lão Tuyền rồi mới ra tay đoạt."},{"chuong":156,"tieuDe":"Bất Lão Tuyền","tomTat":"Nhóc Tỳ (Thạch Hạo) ngồi bên Bất Lão Tuyền, ép các Thái Cổ di chủng đang bị Hoàng Kim thú cưỡng bức hái thuốc phải nộp hết linh dược đổi lấy bình an. Thiếu nữ tóc tím phẫn nộ vì bị chia chác linh dược; Nhóc Tỳ ném cự thạch tấn công nàng nhưng bị trường vực đánh nát thành bột, đành không xuất thủ để chờ cướp sạch về sau. Nó tra hỏi Hoàng Kim thú, dùng ngoan thạch bẻ gãy đoạt hai sừng vàng kim làm thuốc dẫn rồi đập ngất con thú. Thiếu nữ tóc tím kích động các sinh linh liên thủ diệt Nhóc Tỳ trước, buộc nó đeo túi da thú tiến vào trường vực cạnh tranh công bằng, dọc đường thấy tám thi hài nổ tung. Càng vào trong ánh vàng càng đậm, một con chim thần mắt sắc bén xé xác một sinh linh rồi nuốt trái tim bổ sung tinh khí thần. Các sinh linh tiếp cận Bất Lão Tuyền, quyết chiến bùng nổ; Nhóc Tỳ bị móng vuốt đen tấn công và hò hét đòi hàng phục hung thú lẫn chim thần thuần huyết."},{"chuong":157,"tieuDe":"Tất Cả Đều Là Của Ta!","tomTat":"Thạch Hạo (Nhóc Tỳ) giao chiến kịch liệt với Chư Kiền — một Thái Cổ hung thú non thuần huyết mặt người một mắt dọc, thân báo đuôi giao long — cứng chọi cứng làm đất nứt rung ầm ầm, đánh trọng thương và xé được một tảng huyết nhục bảo dược từ tay nó. Cậu dùng Đả Thần Thạch (ngoan thạch) đập địch phát nào trúng phát ấy, còn ném trúng trán thiếu nữ tóc tím hai lần khiến nàng nổi hai cục u như cặp sừng rồng, lần đầu đời bị nhục. Chim thần Tất Phương lao tới nhưng chỉ nhằm đánh Chư Kiền vì đại thù, không liên thủ với ai. Cả nhóm xông vào thần trì Bất Lão Tuyền chịu trường vực khiến động tác chậm chạp và thân thể đau nhức, nhưng phát hiện thần tuyền đã khô cạn chỉ còn bùn cát vàng kim. Thạch Hạo và Ngoan thạch tranh nhau ăn bùn cát, rồi đào ra con rồng nhỏ màu vàng — Bất Lão Tuyền đang lột xác hóa hình; cậu ra tay trước cắn đứt đuôi rồng, rồng gầm thét phá tung tuyền trì rồi hóa hào quang bỏ chạy, cả nhóm đuổi theo trong khi Thạch Hạo giữ chặt đuôi rồng và hò hét đều là của ta."},{"chuong":158,"tieuDe":"Chương 158","tomTat":"Đuôi rồng vàng phân rã thành năm con rồng nhỏ định chạy, Nhóc Tỳ chụp được nhét vào miệng đe dọa rồi nhốt vào bình ngọc; Đả Thần Thạch xác nhận đây là năm giọt Bất Lão Tuyền, còn con rồng vàng lớn (chính chủ) đã hóa hình tỉnh giấc chạy thoát, tương lai có thể thành Tế Linh hay thần linh. Hai đứa tranh nhau ăn sạch cát vàng đã ngâm Bất Lão Tuyền, đào sâu quá ba mét khiến ao thần thành đất bình thường. Ngoan thạch sau khi ăn no buột miệng khoe, bị tra khảo phải thú nhận bốn lần trộm cát thần và việc cắn Thông Linh Hoa rồi chôn xuống đất ăn hết, khiến Nhóc Tỳ giận dữ giẫm đạp. Nhóc Tỳ ra ngoài thu mười một túi cát thần vào túi Càn khôn, quay lại đào tám cây linh dược nguyên rễ, dự tính đem về Thạch thôn tạo đất lành cho Nhân tộc và phân năm giọt cho tộc trưởng, Liễu thần cùng nhóm Đại Tráng. Nó giao chiến Chư Kiền xé thêm huyết nhục bảo dược, đập trán thiếu nữ tóc tím mọc ba bướu rồi bị các sinh linh thuần huyết vây truy sát phải bỏ chạy. Cuối chương, Nhóc Tỳ còn nhổ lông Tất Phương làm quả cầu và lừa Li Long để bóc hai vảy rồng dính máu, kết luận rằng đám sinh linh này tính nết xấu xa khó sống chung."},{"chuong":159,"tieuDe":"Cấm Khu Thiên Cốt","tomTat":"Nhóc Tỳ trộm hai miếng thịt của Chư Kiền rồi trốn khỏi Thần viên/Bách Thảo viên, bị các sinh linh thuần huyết Chư Kiền, Tất Phương, Li Long và thiếu nữ tóc tím hợp sức bao vây truy sát. Ra khỏi vùng tịnh thổ, đám sinh linh bùng phù văn dày đặc như thần khiến nó nhận ra đó là đặc thù khi mở Động Thiên thứ chín; bị đánh hộc máu, nó đành dùng Súc Địa Phù dán vào lòng bàn chân hóa tia sáng thoát thân, khiến bọn Tất Phương sững sờ. Phù này cướp từ nam tử áo xanh Côn tộc trong hồi tưởng — kẻ cùng Người phong ấn Cai tộc truy sát nó, bị nó dùng Long Giao Tiễn đánh chết. Nó dọa luyện ngoan thạch (Đả Thần Thạch) thành chí bảo ép nó thu nhỏ bằng đốt ngón tay, quấn cạnh tháp nhỏ bí ẩn. Sau một đêm, Nhóc Tỳ tiến vào cấm khu Thiên Cốt, phát hiện vùng sương mù xám chất đầy xương trắng và sâu bên trong có sinh linh thuần huyết giao chiến. Ở tuyến khác, thiếu niên Nhân loại Thạch Nghị (Trùng Đồng giả) của Võ Vương phủ đẩy lui thần thú xanh và trấn áp Liệt Thiên Ma Điệp thuần huyết năm lần bằng thần quang ngũ sắc của Ngũ Sắc Khổng Tước Vương, khó gặp địch thủ trong cấm khu."},{"chuong":160,"tieuDe":"Trùng Đồng","tomTat":"Liệt Thiên Ma Điệp — hậu duệ ma thần thời Thái Cổ đã năm lần thất bại — dốc toàn bộ thần lực khiêu chiến trận quyết đấu cuối cùng với Thạch Nghị, hai cánh hóa thành tiên kiếm cùng bảo thuật lôi điện cực mạnh. Thạch Nghị dùng thần thông lôi điện trấn giáo Vũ tộc đối lôi, uy lực hơn cả Vũ tộc, khiến chúng nhân bàn tán về năm loại bảo thuật trấn tộc của hắn mà hai loại vẫn còn bí ẩn. Hắn mở Trùng Đồng Khai Thiên phóng lưới phù văn trói cứng bướm ma, rồi hiển hóa năm Động Thiên, mỗi cái tẩm bổ một sinh linh chí tôn hóa từ phù văn, đánh bại địch lần thứ sáu và thả bướm ma vào vùng cấm Thiên Cốt. Bên ngoài đám đông, Nhóc Tỳ nhai bùn cát thần màu vàng luyện hóa để nâng thực lực, khiến Đả Thần Thạch than đau lòng và cảm nhận cậu chôn giấu điều gì đó rất sâu. Sau nửa canh giờ, một tiếng nổ kinh thiên làm toàn tiểu thế giới rung chuyển, các thông đạo cửa vàng biến mất và các vực nối thông thành chỉnh thể — Bách Đoạn sơn hiện nguyên hình. Thời gian mở cửa sắp kết thúc, dân bản địa mạnh mẽ được giải thoát bắt đầu tàn sát các thiên tài ngoại lai."}];
